    name: string;
    score: number;
    maxScore: number;
    criteria: string;
}

export interface Item {
    name: string;
    standards: Standard[];
}

export interface Deduction {
    item: string;
    standard: string;
    score: number;
    maxScore: number;
    criteria: string;
}

export interface AreaData {
    name?: string; // For display purposes
    items: Item[];
    score: number;
    maxScore: number;
    completed: boolean;
    deductions: Deduction[];
    redLine: string[];
}

export interface Areas {
    [key: string]: AreaData;
    vegetables: AreaData;
    grocery: AreaData;
    seafood: AreaData;
    meat: AreaData;
    deli: AreaData;
    cashier: AreaData;
}

export interface InspectionData {
    inspector: string;
    shop: string;
    date: string;
