import { InspectionData } from "../types";

export function exportToExcel(inspectionData: InspectionData) {
    let totalScore = 0;
    let maxTotalScore = 0;

    Object.keys(inspectionData.areas).forEach(key => {
        const area = inspectionData.areas[key];
        if (area.completed) {
            totalScore += area.score;
            maxTotalScore += area.maxScore;
        }
    });

    const percentage = maxTotalScore > 0 ? (totalScore / maxTotalScore * 100).toFixed(1) : "0.0";

    // 创建HTML表格内容
    let html = `
        <html xmlns:o="urn:schemas-microsoft-com:office:office" xmlns:x="urn:schemas-microsoft-com:office:excel" xmlns="http://www.w3.org/TR/REC-html40">
        <head>
            <meta charset="UTF-8">
            <title>巡店检查报告</title>
            <!--[if gte mso 9]>
            <xml>
                <x:ExcelWorkbook>
                    <x:ExcelWorksheets>
                        <x:ExcelWorksheet>
                            <x:Name>巡店检查报告</x:Name>
                            <x:WorksheetOptions>
                                <x:DisplayGridlines/>
                            </x:WorksheetOptions>
                        </x:ExcelWorksheet>
                    </x:ExcelWorksheets>
                </x:ExcelWorkbook>
            </xml>
            <![endif]-->
            <style>
                table {
                    border-collapse: collapse;
                    width: 100%;
                }
                th, td {
                    border: 1px solid #ddd;
                    padding: 8px;
                    text-align: left;
                }
                th {
                    background-color: #3498db;
                    color: white;
                }
                .deduction-item {
                    color: #e74c3c;
                    margin-left: 20px;
                }
            </style>
        </head>
        <body>
            <h1>巡店检查报告</h1>
            <p>检查人: ${inspectionData.inspector}</p>
            <p>门店名称: ${inspectionData.shop}</p>
            <p>检查日期: ${inspectionData.date}</p>

            <h2>总分: ${totalScore} / ${maxTotalScore} (${percentage}%)</h2>

            <h3>各区域得分汇总</h3>
            <table>
                <tr>
                    <th>区域</th>
                    <th>得分</th>
                    <th>满分</th>
                    <th>百分比</th>
                </tr>
    `;

    // 添加各区域得分
    for (const areaKey in inspectionData.areas) {
        const area = inspectionData.areas[areaKey];
        if (area.completed) {
            let areaName = area.name || "";
            if (!areaName) {
                switch(areaKey) {
                    case 'vegetables': areaName = '蔬果区'; break;
                    case 'grocery': areaName = '食百区'; break;
                    case 'seafood': areaName = '水产区'; break;
                    case 'meat': areaName = '肉品区'; break;
                    case 'deli': areaName = '熟食区'; break;
                    case 'cashier': areaName = '收银区域'; break;
                }
            }

            const areaPercentage = area.maxScore > 0 ? (area.score / area.maxScore * 100).toFixed(1) : "0.0";

            html += `
                <tr>
                    <td>${areaName}</td>
                    <td>${area.score}</td>
                    <td>${area.maxScore}</td>
                    <td>${areaPercentage}%</td>
                </tr>
            `;
        }
    }

    html += `
            </table>

            <h3>详细扣分项</h3>
    `;

    // 添加详细扣分项
    for (const areaKey in inspectionData.areas) {
        const area = inspectionData.areas[areaKey];
        if (area.completed && area.deductions.length > 0) {
            let areaName = area.name || "";
            // Fallback for names if not provided in data object directly
             if (!areaName) {
                switch(areaKey) {
                    case 'vegetables': areaName = '蔬果区'; break;
                    case 'grocery': areaName = '食百区'; break;
                    case 'seafood': areaName = '水产区'; break;
                    case 'meat': areaName = '肉品区'; break;
                    case 'deli': areaName = '熟食区'; break;
                    case 'cashier': areaName = '收银区域'; break;
                }
            }

            html += `<h4>${areaName}</h4><table>`;
            html += `
                <tr>
                    <th>检查项目</th>
                    <th>检查标准</th>
                    <th>得分</th>
                    <th>满分</th>
                    <th>扣分原因</th>
                </tr>
            `;

            area.deductions.forEach(deduction => {
                html += `
                    <tr>
                        <td>${deduction.item}</td>
                        <td>${deduction.standard}</td>
                        <td>${deduction.score}</td>
                        <td>${deduction.maxScore}</td>
                        <td>${deduction.criteria}</td>
                    </tr>
                `;
            });

            html += `</table>`;
        }
    }

    // 添加红线条款
    html += `<h3>红线条款</h3><ul>`;
    for (const areaKey in inspectionData.areas) {
        const area = inspectionData.areas[areaKey];
        if (area.completed) {
            let areaName = area.name || "";
             if (!areaName) {
                switch(areaKey) {
                    case 'vegetables': areaName = '蔬果区'; break;
                    case 'grocery': areaName = '食百区'; break;
                    case 'seafood': areaName = '水产区'; break;
                    case 'meat': areaName = '肉品区'; break;
                    case 'deli': areaName = '熟食区'; break;
                    case 'cashier': areaName = '收银区域'; break;
                }
            }

            html += `<li><strong>${areaName}:</strong><ul>`;
            area.redLine.forEach(item => {
                html += `<li>${item}</li>`;
            });
            html += `</ul></li>`;
        }
    }
    html += `</ul>`;

    html += `
        </body>
        </html>
    `;

    // 创建Blob对象
    const blob = new Blob([html], { type: 'application/vnd.ms-excel' });

    // 创建下载链接
    const a = document.createElement('a');
    a.href = URL.createObjectURL(blob);
    a.download = `巡店检查报告_${inspectionData.shop}_${inspectionData.date.replace(/[: ]/g, '-')}.xls`;

    // 触发下载
    document.body.appendChild(a);
    a.click();

    // 清理
    setTimeout(() => {
        document.body.removeChild(a);
        URL.revokeObjectURL(a.href);
    }, 100);
}

import React, { useState, useEffect } from 'react';
import { InspectionData, ViewState, Areas, AreaData, Deduction } from './types';
import { INITIAL_AREAS } from './data';
import { exportToExcel } from './utils/excelExport';

const App: React.FC = () => {
    // Application State
    const [view, setView] = useState<ViewState>('inspector-info');
    const [currentAreaKey, setCurrentAreaKey] = useState<string>('');
    const [inspectionData, setInspectionData] = useState<InspectionData>({
        inspector: '',
        shop: '',
        date: '',
        areas: JSON.parse(JSON.stringify(INITIAL_AREAS)) // Deep copy to ensure fresh state
    });

    // Initialize Date
    useEffect(() => {
        const now = new Date();
        const formattedDate = now.getFullYear() + '-' + 
                             String(now.getMonth() + 1).padStart(2, '0') + '-' + 
                             String(now.getDate()).padStart(2, '0') + ' ' + 
                             String(now.getHours()).padStart(2, '0') + ':' + 
                             String(now.getMinutes()).padStart(2, '0');

        setInspectionData(prev => ({ ...prev, date: formattedDate }));
    }, []);

    // --- Actions ---

    const handleStartInspection = (inspector: string, shop: string) => {
        if (!inspector || !shop) {
            alert('请填写检查人姓名和门店名称');
            return;
        }
        setInspectionData(prev => ({ ...prev, inspector, shop }));
        setView('area-selection');
    };

    const handleSelectArea = (areaKey: string) => {
        setCurrentAreaKey(areaKey);
        setView('inspection');
    };

    const handleViewResults = () => {
        setView('results');
    };

    const handleBackToAreas = () => {
        setView('area-selection');
    };

    const handleUpdateScore = (itemIndex: number, standardIndex: number, newScore: number) => {
        setInspectionData(prev => {
            const newData = { ...prev };
            const area = newData.areas[currentAreaKey];
            area.items[itemIndex].standards[standardIndex].score = newScore;
            return newData;
        });
    };

    const handleConfirmInspection = () => {
        if (window.confirm('确认提交当前区域的检查评分吗？')) {
            setInspectionData(prev => {
                const newData = { ...prev };
                const area = newData.areas[currentAreaKey];

                let totalScore = 0;
                let maxScore = 0;
                const deductions: Deduction[] = [];

                area.items.forEach(item => {
                    item.standards.forEach(standard => {
                        totalScore += standard.score;
                        maxScore += standard.maxScore;

                        if (standard.score < standard.maxScore) {
                            deductions.push({
                                item: item.name,
                                standard: standard.name,
                                score: standard.score,
                                maxScore: standard.maxScore,
                                criteria: standard.criteria
                            });
                        }
                    });
                });

                area.score = totalScore;
                area.maxScore = maxScore;
                area.completed = true;
                area.deductions = deductions;
                return newData;
            });
            handleBackToAreas();
        }
