    const handleCancelInspection = () => {
         if (window.confirm('确定要取消当前检查吗？未保存的评分将丢失。')) {
            // Need to reset the current area data to what it was before? 
            // The original app didn't actually revert data, just navigated back. 
            // But since we modify state in real-time, "cancelling" implies 
            // we should probably revert or just accept that state persists until reset.
            // The original code: "backToAreas()" simply hides the div. It keeps the modifications in memory 
            // until the user comes back or reloads. However, the alert says "unsaved ratings will be lost".
            // To be faithful to the *implied* behavior of "Cancel", usually we reload or reset.
            // But strict adherence to "unchanged form" suggests we just go back.
            // Wait, the original HTML modifies `inspectionData` global object directly on `change` event.
            // So `cancel` in the original HTML effectively just went back but kept the data in the global variable 
            // because there was no deep copy reset mechanism implemented in the `cancelInspection` function provided.
            // It just called `backToAreas()`.
