    const handleUpdateScore = (itemIndex: number, standardIndex: number, newScore: number) => {
        setInspectionData(prev => {
            // Create a deep enough copy to avoid direct mutation
            const newAreas = { ...prev.areas };
            const newArea = { ...newAreas[currentAreaKey] };
            const newItems = [...newArea.items];
            const newItem = { ...newItems[itemIndex] };
            const newStandards = [...newItem.standards];
            const newStandard = { ...newStandards[standardIndex] };

            newStandard.score = newScore;

            // Reassemble
            newStandards[standardIndex] = newStandard;
            newItem.standards = newStandards;
            newItems[itemIndex] = newItem;
            newArea.items = newItems;
            newAreas[currentAreaKey] = newArea;

            return { ...prev, areas: newAreas };
        });
    };

    const handleConfirmInspection = () => {
        if (window.confirm('确认提交当前区域的检查评分吗？')) {
            setInspectionData(prev => {
                const newAreas = { ...prev.areas };
                const newArea = { ...newAreas[currentAreaKey] };

                let totalScore = 0;
                let maxScore = 0;
                const deductions: Deduction[] = [];

                newArea.items.forEach(item => {
                    item.standards.forEach(standard => {
                        totalScore += standard.score;
                        maxScore += standard.maxScore;

                        if (standard.score < standard.maxScore) {
                            deductions.push({
                                item: item.name,
                                standard: standard.name,
                                score: standard.score,
                                maxScore: standard.maxScore,
                                criteria: standard.criteria
                            });
                        }
                    });
                });

                newArea.score = totalScore;
                newArea.maxScore = maxScore;
                newArea.completed = true;
                newArea.deductions = deductions;

                newAreas[currentAreaKey] = newArea;

                return { ...prev, areas: newAreas };
            });
            handleBackToAreas();
        }
    };

    const handleCancelInspection = () => {
         if (window.confirm('确定要取消当前检查吗？未保存的评分将丢失。')) {
            handleBackToAreas();
        }
    };

    // --- Renderers ---

    const renderInspectorInfo = () => (
        <div id="inspector-info-page">
            <div className="bg-[#3498db] text-white p-[15px] rounded-[5px] mb-[20px]">
                <h1 className="text-center text-2xl font-bold">超市巡店检查评分系统</h1>
            </div>
            <div className="mb-[15px]">
                <label className="block mb-[5px] font-bold">检查人姓名 (Inspector Name):</label>
                <input 
                    type="text" 
                    className="w-full p-[8px] border border-[#ddd] rounded-[4px] box-border"
                    value={inspectionData.inspector}
                    onChange={(e) => setInspectionData(prev => ({...prev, inspector: e.target.value}))}
                    required 
                />
            </div>
            <div className="mb-[15px]">
                <label className="block mb-[5px] font-bold">门店名称 (Shop Name):</label>
                <input 
                    type="text" 
                    className="w-full p-[8px] border border-[#ddd] rounded-[4px] box-border"
                    value={inspectionData.shop}
                    onChange={(e) => setInspectionData(prev => ({...prev, shop: e.target.value}))}
                    required 
                />
            </div>
            <div className="mb-[15px]">
                <label className="block mb-[5px] font-bold">检查日期 (Inspection Date):</label>
                <input 
                    type="text" 
                    className="w-full p-[8px] border border-[#ddd] rounded-[4px] box-border bg-gray-100"
                    value={inspectionData.date}
                    readOnly 
                />
            </div>
            <button 
                className="bg-[#27ae60] text-white border-none py-[10px] px-[15px] rounded-[4px] cursor-pointer text-[16px] m-[5px] hover:bg-[#219653] transition-colors duration-300"
                onClick={() => handleStartInspection(inspectionData.inspector, inspectionData.shop)}
            >
                开始检查
            </button>
        </div>
    );

    const renderAreaSelection = () => (
        <div id="area-selection-page">
            <div className="bg-[#3498db] text-white p-[15px] rounded-[5px] mb-[20px]">
                <h2 className="text-center text-xl font-bold">请选择检查区域</h2>
                <p className="text-center mt-2">检查人: <span>{inspectionData.inspector}</span> | 门店: <span>{inspectionData.shop}</span> | 日期: <span>{inspectionData.date}</span></p>
            </div>
            <div className="flex flex-wrap justify-center gap-[10px] my-[20px]">
                {[
                    { key: 'vegetables', label: '蔬果区', sub: 'Vegetables & Fruits' },
                    { key: 'grocery', label: '食百区', sub: 'Food & Grocery' },
                    { key: 'seafood', label: '水产区', sub: 'SeaFood' },
                    { key: 'meat', label: '肉品区', sub: 'Meat' },
                    { key: 'deli', label: '熟食区', sub: 'Deli' },
                    { key: 'cashier', label: '收银区域', sub: 'Cashier' }
                ].map(area => {
                    const isCompleted = inspectionData.areas[area.key]?.completed;
                    return (
                        <button 
                            key={area.key}
                            className={`${isCompleted ? 'bg-[#27ae60] hover:bg-[#219653]' : 'bg-[#3498db] hover:bg-[#2980b9]'} text-white border-none min-w-[120px] md:min-w-[150px] p-[10px] md:p-[15px] rounded-[4px] cursor-pointer text-[14px] md:text-[16px] transition-colors duration-300`}
                            onClick={() => handleSelectArea(area.key)}
                        >
                            {area.label}{isCompleted && " (已完成)"}<br />{area.sub}
                        </button>
                    );
                })}
            </div>
            <button 
                className="bg-[#7f8c8d] text-white border-none py-[10px] px-[15px] rounded-[4px] cursor-pointer text-[16px] m-[5px] hover:bg-[#6c7a7d] transition-colors duration-300"
                onClick={handleViewResults}
            >
                查看检查结果
            </button>
        </div>
    );

    const renderInspectionPage = () => {
        const area = inspectionData.areas[currentAreaKey];
        if (!area) return null;

        return (
            <div id="inspection-page">
                <div className="bg-[#3498db] text-white p-[15px] rounded-[5px] mb-[20px]">
                    <h2 className="text-center text-xl font-bold">{area.name}</h2>
                    <p className="text-center mt-2">检查人: <span>{inspectionData.inspector}</span> | 门店: <span>{inspectionData.shop}</span> | 日期: <span>{inspectionData.date}</span></p>
                </div>

                <div className="my-[20px] flex justify-between items-center">
                    <div>
                        <input 
                            type="text" 
                            placeholder="搜索检查项目..." 
                            className="w-[200px] md:w-[300px] p-[8px] border border-[#ddd] rounded-[4px] box-border"
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                        />
                    </div>
                    <div>
                        <button 
                            className="bg-[#7f8c8d] text-white border-none py-[10px] px-[15px] rounded-[4px] cursor-pointer text-[14px] md:text-[16px] m-[5px] hover:bg-[#6c7a7d] transition-colors duration-300"
                            onClick={handleBackToAreas}
                        >
                            返回区域选择
                        </button>
                    </div>
                </div>

                <div id="inspection-items-container">
                    {area.items.map((item, itemIdx) => {
                        // Filter logic
                        if (searchTerm && !item.name.toLowerCase().includes(searchTerm.toLowerCase())) {
                            return null;
                        }

                        return (
                            <div key={itemIdx} className="bg-[#f9f9f9] border border-[#ddd] rounded-[5px] p-[15px] mb-[15px]">
                                <h3 className="text-[#2c3e50] text-lg font-bold mb-2 text-center">{item.name}</h3>
                                {item.standards.map((standard, stdIdx) => (
                                    <div key={stdIdx} className="ml-[20px] mb-[10px] p-[10px] bg-[#ecf0f1] rounded-[4px]">
