                                        <p className="text-[14px] color-[#7f8c8d] mt-[5px] text-gray-500">评分标准: {standard.criteria}</p>
                                        <div className="flex items-center mt-[5px]">
                                            <select 
                                                className="w-[80px] mr-[10px] p-[8px] border border-[#ddd] rounded-[4px]"
                                                value={standard.score}
                                                onChange={(e) => handleUpdateScore(itemIdx, stdIdx, parseInt(e.target.value))}
                                            >
                                                {Array.from({ length: standard.maxScore + 1 }, (_, i) => standard.maxScore - i).map(score => (
                                                    <option key={score} value={score}>{score}分</option>
                                                ))}
                                            </select>
                                            <span> / {standard.maxScore}分</span>
                                        </div>
                                    </div>
                                ))}
                            </div>
                        );
                    })}
                </div>

                <div className="text-[#e74c3c] font-bold my-[15px] p-[10px] bg-[#fdeaea] border-l-4 border-[#e74c3c]">
                    <h3 className="text-center text-[#2c3e50]">红线条款 (Red Line Terms):</h3>
                    {area.redLine.map((line, idx) => (
                        <p key={idx}>{line}</p>
                    ))}
                </div>

                <div className="mt-[30px] pt-[20px] border-t border-dashed border-[#ccc]">
                    <p>巡店人签名 (Inspector Signature): _________________________</p>
                </div>

                <div className="text-center mt-[20px]">
                    <button 
                        className="bg-[#27ae60] text-white border-none py-[10px] px-[15px] rounded-[4px] cursor-pointer text-[16px] m-[5px] hover:bg-[#219653] transition-colors duration-300"
                        onClick={handleConfirmInspection}
                    >
                        确认检查
                    </button>
                    <button 
                        className="bg-[#7f8c8d] text-white border-none py-[10px] px-[15px] rounded-[4px] cursor-pointer text-[16px] m-[5px] hover:bg-[#6c7a7d] transition-colors duration-300"
                        onClick={handleCancelInspection}
                    >
                        取消
                    </button>
                </div>
            </div>
        );
    };

    const renderResultsPage = () => {
        let totalScore = 0;
        let maxTotalScore = 0;
        const completedAreas: { key: string; data: AreaData }[] = [];

        Object.keys(inspectionData.areas).forEach(key => {
            const area = inspectionData.areas[key];
            if (area.completed) {
                totalScore += area.score;
                maxTotalScore += area.maxScore;
                completedAreas.push({ key, data: area });
            }
        });

        const overallPercentage = maxTotalScore > 0 ? (totalScore / maxTotalScore * 100).toFixed(1) : '0';

        return (
            <div id="results-page">
                <div className="bg-[#3498db] text-white p-[15px] rounded-[5px] mb-[20px]">
                    <h2 className="text-center text-xl font-bold">巡店检查结果</h2>
                    <p className="text-center mt-2">检查人: <span>{inspectionData.inspector}</span> | 门店: <span>{inspectionData.shop}</span> | 日期: <span>{inspectionData.date}</span></p>
                </div>

                <div className="text-[18px] font-bold my-[20px] text-center">
                    总分 (Total Score): <span>{totalScore}</span> / <span>{maxTotalScore}</span>
                    (<span>{overallPercentage}</span>%)
                </div>

                <table className="w-full border-collapse my-[20px]">
                    <thead>
                        <tr>
                            <th className="border border-[#ddd] p-[8px] text-left bg-[#3498db] text-white">区域 (Area)</th>
                            <th className="border border-[#ddd] p-[8px] text-left bg-[#3498db] text-white">得分 (Score)</th>
                            <th className="border border-[#ddd] p-[8px] text-left bg-[#3498db] text-white">满分 (Max Score)</th>
                            <th className="border border-[#ddd] p-[8px] text-left bg-[#3498db] text-white">百分比 (%)</th>
                        </tr>
                    </thead>
                    <tbody>
                        {completedAreas.map(({ key, data }, idx) => {
                            const pct = data.maxScore > 0 ? (data.score / data.maxScore * 100).toFixed(1) : '0';
                            return (
                                <tr key={key} className={idx % 2 === 0 ? "bg-[#f2f2f2]" : ""}>
                                    <td className="border border-[#ddd] p-[8px]">{data.name}</td>
                                    <td className="border border-[#ddd] p-[8px]">{data.score}</td>
                                    <td className="border border-[#ddd] p-[8px]">{data.maxScore}</td>
                                    <td className="border border-[#ddd] p-[8px]">{pct}%</td>
                                </tr>
                            );
                        })}
                    </tbody>
                </table>

                <div className="mt-[30px]">
                    <h3 className="text-[#2c3e50] font-bold text-center text-lg mb-2">详细扣分项:</h3>
                    {completedAreas.map(({ key, data }) => {
                        if (data.deductions.length === 0) return null;
                        return (
                            <div key={key}>
                                <h4 className="text-[#2c3e50] font-bold mt-4 mb-2">{data.name}扣分项:</h4>
                                <ul className="list-disc pl-5">
                                    {data.deductions.map((deduction, dIdx) => (
                                        <li key={dIdx} className="text-[#e74c3c] ml-[20px] mb-2">
                                            <strong>{deduction.item}</strong> - {deduction.standard}<br/>
                                            得分: {deduction.score}/{deduction.maxScore}<br/>
                                            扣分原因: {deduction.criteria}
                                        </li>
                                    ))}
                                </ul>
                            </div>
                        );
                    })}
                </div>

                <div className="text-center mt-[20px]">
                    <button 
                        className="bg-[#27ae60] text-white border-none py-[10px] px-[15px] rounded-[4px] cursor-pointer text-[16px] m-[5px] hover:bg-[#219653] transition-colors duration-300"
                        onClick={() => exportToExcel(inspectionData)}
                    >
                        导出详细报告
                    </button>
                    <button 
                        className="bg-[#7f8c8d] text-white border-none py-[10px] px-[15px] rounded-[4px] cursor-pointer text-[16px] m-[5px] hover:bg-[#6c7a7d] transition-colors duration-300"
                        onClick={handleBackToAreas}
                    >
                        返回区域选择
                    </button>
                </div>
            </div>
        );
    };

    return (
        <div className="container max-w-[1200px] mx-auto bg-white p-[10px] md:p-[20px] rounded-[8px] shadow-[0_0_10px_rgba(0,0,0,0.1)]">
            {view === 'inspector-info' && renderInspectorInfo()}
            {view === 'area-selection' && renderAreaSelection()}
            {view === 'inspection' && renderInspectionPage()}
            {view === 'results' && renderResultsPage()}
        </div>
    );
};

