import React, { useState, useEffect } from 'react';
import { InspectionData, ViewState, Areas, AreaData, Deduction } from './types';
import { INITIAL_AREAS } from './data';
import { exportToExcel } from './utils/excelExport';

const App: React.FC = () => {
    // Application State
    // Use lazy initialization for heavy initial state (deep copy of large data)
    const [inspectionData, setInspectionData] = useState<InspectionData>(() => ({
        inspector: '',
        shop: '',
        date: '',
        areas: JSON.parse(JSON.stringify(INITIAL_AREAS)) // Deep copy to ensure fresh state
    }));

    const [view, setView] = useState<ViewState>('inspector-info');
    const [currentAreaKey, setCurrentAreaKey] = useState<string>('');
    const [searchTerm, setSearchTerm] = useState<string>('');

    // Initialize Date
    useEffect(() => {
        const now = new Date();
        const formattedDate = now.getFullYear() + '-' + 
                             String(now.getMonth() + 1).padStart(2, '0') + '-' + 
                             String(now.getDate()).padStart(2, '0') + ' ' + 
                             String(now.getHours()).padStart(2, '0') + ':' + 
                             String(now.getMinutes()).padStart(2, '0');

        setInspectionData(prev => ({ ...prev, date: formattedDate }));
    }, []);

    // --- Actions ---

    const handleStartInspection = (inspector: string, shop: string) => {
        if (!inspector || !shop) {
            alert('请填写检查人姓名和门店名称');
            return;
        }
        setInspectionData(prev => ({ ...prev, inspector, shop }));
        setView('area-selection');
    };

    const handleSelectArea = (areaKey: string) => {
        setCurrentAreaKey(areaKey);
        setSearchTerm('');
        setView('inspection');
    };

    const handleViewResults = () => {
        setView('results');
    };

    const handleBackToAreas = () => {
        setView('area-selection');
    };

    const handleUpdateScore = (itemIndex: number, standardIndex: number, newScore: number) => {
        setInspectionData(prev => {
            // Create a deep enough copy to avoid direct mutation
            const newAreas = { ...prev.areas };
            const newArea = { ...newAreas[currentAreaKey] };

            // Deep copy items array
            newArea.items = newArea.items.map((item, idx) => {
                if (idx !== itemIndex) return item;
                return {
                    ...item,
                    standards: item.standards.map((std, sIdx) => {
                        if (sIdx !== standardIndex) return std;
                        return { ...std, score: newScore };
                    })
                };
            });

            newAreas[currentAreaKey] = newArea;
            return { ...prev, areas: newAreas };
        });
    };

    const handleConfirmInspection = () => {
        if (!currentAreaKey) return;

        try {
            if (window.confirm('确认提交当前区域的检查评分吗？')) {
                // Perform calculation inside the state setter to guarantee we use the most recent state
                setInspectionData(prev => {
                    const newAreas = { ...prev.areas };
                    const currentArea = newAreas[currentAreaKey];

                    if (!currentArea) return prev;

                    let totalScore = 0;
                    let maxScore = 0;
                    const deductions: Deduction[] = [];

                    currentArea.items.forEach(item => {
                        item.standards.forEach(standard => {
                            totalScore += standard.score;
                            maxScore += standard.maxScore;

                            if (standard.score < standard.maxScore) {
                                deductions.push({
                                    item: item.name,
                                    standard: standard.name,
                                    score: standard.score,
                                    maxScore: standard.maxScore,
                                    criteria: standard.criteria
                                });
                            }
                        });
                    });

                    // Update the area metadata
                    newAreas[currentAreaKey] = {
                        ...currentArea,
                        score: totalScore,
                        maxScore: maxScore,
                        completed: true,
                        deductions: deductions
                    };

                    return { ...prev, areas: newAreas };
                });

                // Navigate back to area selection
                setView('area-selection');
            }
        } catch (e) {
            console.error("Error confirming inspection:", e);
            alert("提交出错，请重试");
        }
    };

    const handleCancelInspection = () => {
         if (window.confirm('确定要取消当前检查吗？未保存的评分将丢失。')) {
