                        返回区域选择
                    </button>
                </div>
            </div>
        );
    };

    return (
        <div className="container max-w-[1200px] mx-auto bg-white p-[10px] md:p-[20px] rounded-[8px] shadow-[0_0_10px_rgba(0,0,0,0.1)]">
            {view === 'inspector-info' && renderInspectorInfo()}
            {view === 'area-selection' && renderAreaSelection()}
            {view === 'inspection' && renderInspectionPage()}
            {view === 'results' && renderResultsPage()}
        </div>
    );
};

export default App;

import React, { useState, useEffect } from 'react';
import { InspectionData, ViewState, Areas, AreaData, Deduction } from './types';
import { INITIAL_AREAS } from './data';
import { exportToExcel } from './utils/excelExport';

const App: React.FC = () => {
    // Application State
    const [inspectionData, setInspectionData] = useState<InspectionData>(() => ({
        inspector: '',
        shop: '',
        date: '',
        areas: JSON.parse(JSON.stringify(INITIAL_AREAS)) // Deep copy to ensure fresh state
    }));

    const [view, setView] = useState<ViewState>('inspector-info');
    const [currentAreaKey, setCurrentAreaKey] = useState<string>('');
    const [searchTerm, setSearchTerm] = useState<string>('');

    // Initialize Date
    useEffect(() => {
        const now = new Date();
        const formattedDate = now.getFullYear() + '-' + 
                             String(now.getMonth() + 1).padStart(2, '0') + '-' + 
                             String(now.getDate()).padStart(2, '0') + ' ' + 
                             String(now.getHours()).padStart(2, '0') + ':' + 
                             String(now.getMinutes()).padStart(2, '0');

        setInspectionData(prev => ({ ...prev, date: formattedDate }));
    }, []);

    // --- Actions ---

    const handleStartInspection = (inspector: string, shop: string) => {
        if (!inspector || !shop) {
            alert('请填写检查人姓名和门店名称');
            return;
        }
        setInspectionData(prev => ({ ...prev, inspector, shop }));
        setView('area-selection');
    };

    const handleSelectArea = (areaKey: string) => {
        setCurrentAreaKey(areaKey);
        setSearchTerm('');
        setView('inspection');
    };

    const handleViewResults = () => {
        setView('results');
    };

    const handleBackToAreas = () => {
        setView('area-selection');
    };

    const handleUpdateScore = (itemIndex: number, standardIndex: number, newScore: number) => {
        setInspectionData(prev => {
            // Create a deep enough copy to avoid direct mutation
            const newAreas = { ...prev.areas };
            const newArea = { ...newAreas[currentAreaKey] };

            // Deep copy items array to ensure React detects the change
            newArea.items = newArea.items.map((item, idx) => {
                if (idx !== itemIndex) return item;
                return {
                    ...item,
                    standards: item.standards.map((std, sIdx) => {
                        if (sIdx !== standardIndex) return std;
                        return { ...std, score: newScore };
                    })
                };
            });

            newAreas[currentAreaKey] = newArea;
            return { ...prev, areas: newAreas };
        });
    };

    const handleConfirmInspection = () => {
        if (!currentAreaKey) return;

        // Alternative Approach:
        // 1. Remove window.confirm which might be blocked or failing silently in some views.
        // 2. Calculate logic OUTSIDE the setInspectionData to ensure we are working with the latest render scope variables.
        // 3. Add an explicit alert() to give user feedback that "something happened".

        const currentArea = inspectionData.areas[currentAreaKey];
        if (!currentArea) return;

        // --- Calculation Logic ---
        let totalScore = 0;
        let maxScore = 0;
        const deductions: Deduction[] = [];

        currentArea.items.forEach(item => {
            item.standards.forEach(standard => {
                totalScore += standard.score;
                maxScore += standard.maxScore;

                if (standard.score < standard.maxScore) {
                    deductions.push({
                        item: item.name,
                        standard: standard.name,
                        score: standard.score,
                        maxScore: standard.maxScore,
                        criteria: standard.criteria
                    });
                }
            });
        });

        // --- State Update ---
        setInspectionData(prev => {
            const newAreas = { ...prev.areas };
            // Update the specific area with results
            newAreas[currentAreaKey] = {
                ...currentArea, // Keep the items with their scores
                score: totalScore,
                maxScore: maxScore,
                completed: true,
                deductions: deductions
            };

            return {
                ...prev,
                areas: newAreas
            };
        });

        // --- Feedback & Navigation ---
        // Force a browser paint/interaction
        alert("提交成功！(Submitted Successfully)");
        setView('area-selection');
    };

    const handleCancelInspection = () => {
         if (window.confirm('确定要取消当前检查吗？未保存的评分将丢失。')) {
            handleBackToAreas();
        }
    };

    // --- Renderers ---

    const renderInspectorInfo = () => (
        <div id="inspector-info-page">
            <div className="bg-[#3498db] text-white p-[15px] rounded-[5px] mb-[20px]">
                <h1 className="text-center text-2xl font-bold">超市巡店检查评分系统</h1>
            </div>
            <div className="mb-[15px]">
                <label className="block mb-[5px] font-bold">检查人姓名 (Inspector Name):</label>
                <input 
                    type="text" 
                    className="w-full p-[8px] border border-[#ddd] rounded-[4px] box-border"
                    value={inspectionData.inspector}
                    onChange={(e) => setInspectionData(prev => ({...prev, inspector: e.target.value}))}
                    required 
                />
            </div>
            <div className="mb-[15px]">
                <label className="block mb-[5px] font-bold">门店名称 (Shop Name):</label>
                <input 
                    type="text" 
                    className="w-full p-[8px] border border-[#ddd] rounded-[4px] box-border"
                    value={inspectionData.shop}
                    onChange={(e) => setInspectionData(prev => ({...prev, shop: e.target.value}))}
                    required 
                />
            </div>
            <div className="mb-[15px]">
                <label className="block mb-[5px] font-bold">检查日期 (Inspection Date):</label>
                <input 
                    type="text" 
                    className="w-full p-[8px] border border-[#ddd] rounded-[4px] box-border bg-gray-100"
                    value={inspectionData.date}
                    readOnly 
                />
            </div>
            <button 
                type="button"
                className="bg-[#27ae60] text-white border-none py-[10px] px-[15px] rounded-[4px] cursor-pointer text-[16px] m-[5px] hover:bg-[#219653] transition-colors duration-300"
                onClick={() => handleStartInspection(inspectionData.inspector, inspectionData.shop)}
            >
                开始检查
            </button>
        </div>
    );

    const renderAreaSelection = () => (
        <div id="area-selection-page">
            <div className="bg-[#3498db] text-white p-[15px] rounded-[5px] mb-[20px]">
                <h2 className="text-center text-xl font-bold">请选择检查区域</h2>
                <p className="text-center mt-2">检查人: <span>{inspectionData.inspector}</span> | 门店: <span>{inspectionData.shop}</span> | 日期: <span>{inspectionData.date}</span></p>
            </div>
            <div className="flex flex-wrap justify-center gap-[10px] my-[20px]">
                {[
                    { key: 'vegetables', label: '蔬果区', sub: 'Vegetables & Fruits' },
                    { key: 'grocery', label: '食百区', sub: 'Food & Grocery' },
                    { key: 'seafood', label: '水产区', sub: 'SeaFood' },
                    { key: 'meat', label: '肉品区', sub: 'Meat' },
                    { key: 'deli', label: '熟食区', sub: 'Deli' },
                    { key: 'cashier', label: '收银区域', sub: 'Cashier' }
                ].map(area => {
                    const isCompleted = inspectionData.areas[area.key]?.completed;
                    return (
                        <button 
                            key={area.key}
                            type="button"
                            className={`${isCompleted ? 'bg-[#27ae60] hover:bg-[#219653]' : 'bg-[#3498db] hover:bg-[#2980b9]'} text-white border-none min-w-[120px] md:min-w-[150px] p-[10px] md:p-[15px] rounded-[4px] cursor-pointer text-[14px] md:text-[16px] transition-colors duration-300`}
                            onClick={() => handleSelectArea(area.key)}
                        >
                            {area.label}{isCompleted && " (已完成)"}<br />{area.sub}
                        </button>
                    );
                })}
            </div>
            <button 
                type="button"
                className="bg-[#7f8c8d] text-white border-none py-[10px] px-[15px] rounded-[4px] cursor-pointer text-[16px] m-[5px] hover:bg-[#6c7a7d] transition-colors duration-300"
                onClick={handleViewResults}
            >
                查看检查结果
            </button>
        </div>
    );

    const renderInspectionPage = () => {
        const area = inspectionData.areas[currentAreaKey];
        if (!area) return null;

        return (
            <div id="inspection-page">
                <div className="bg-[#3498db] text-white p-[15px] rounded-[5px] mb-[20px]">
                    <h2 className="text-center text-xl font-bold">{area.name}</h2>
                    <p className="text-center mt-2">检查人: <span>{inspectionData.inspector}</span> | 门店: <span>{inspectionData.shop}</span> | 日期: <span>{inspectionData.date}</span></p>
                </div>

                <div className="my-[20px] flex justify-between items-center">
                    <div>
                        <input 
                            type="text" 
                            placeholder="搜索检查项目..." 
                            className="w-[200px] md:w-[300px] p-[8px] border border-[#ddd] rounded-[4px] box-border"
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                        />
                    </div>
                    <div>
                        <button 
                            type="button"
                            className="bg-[#7f8c8d] text-white border-none py-[10px] px-[15px] rounded-[4px] cursor-pointer text-[14px] md:text-[16px] m-[5px] hover:bg-[#6c7a7d] transition-colors duration-300"
                            onClick={handleBackToAreas}
                        >
                            返回区域选择
                        </button>
                    </div>
                </div>

                <div id="inspection-items-container">
                    {area.items.map((item, itemIdx) => {
                        // Filter logic
                        if (searchTerm && !item.name.toLowerCase().includes(searchTerm.toLowerCase())) {
                            return null;
                        }

                        return (
                            <div key={itemIdx} className="bg-[#f9f9f9] border border-[#ddd] rounded-[5px] p-[15px] mb-[15px]">
                                <h3 className="text-[#2c3e50] text-lg font-bold mb-2 text-center">{item.name}</h3>
                                {item.standards.map((standard, stdIdx) => (
                                    <div key={stdIdx} className="ml-[20px] mb-[10px] p-[10px] bg-[#ecf0f1] rounded-[4px]">
                                        <p className="font-bold mb-[5px]">{standard.name}</p>
                                        <p className="text-[14px] color-[#7f8c8d] mt-[5px] text-gray-500">评分标准: {standard.criteria}</p>
                                        <div className="flex items-center mt-[5px]">
                                            <select 
                                                className="w-[80px] mr-[10px] p-[8px] border border-[#ddd] rounded-[4px]"
                                                value={standard.score}
                                                onChange={(e) => handleUpdateScore(itemIdx, stdIdx, parseInt(e.target.value))}
                                            >
                                                {Array.from({ length: standard.maxScore + 1 }, (_, i) => standard.maxScore - i).map(score => (
                                                    <option key={score} value={score}>{score}分</option>
                                                ))}
                                            </select>
                                            <span> / {standard.maxScore}分</span>
                                        </div>
                                    </div>
                                ))}
                            </div>
                        );
                    })}
                </div>

                <div className="text-[#e74c3c] font-bold my-[15px] p-[10px] bg-[#fdeaea] border-l-4 border-[#e74c3c]">
                    <h3 className="text-center text-[#2c3e50]">红线条款 (Red Line Terms):</h3>
                    {area.redLine.map((line, idx) => (
                        <p key={idx}>{line}</p>
                    ))}
                </div>

                <div className="mt-[30px] pt-[20px] border-t border-dashed border-[#ccc]">
                    <p>巡店人签名 (Inspector Signature): _________________________</p>
                </div>

                <div className="text-center mt-[20px]">
                    <button 
                        type="button"
                        className="bg-[#27ae60] text-white border-none py-[10px] px-[15px] rounded-[4px] cursor-pointer text-[16px] m-[5px] hover:bg-[#219653] transition-colors duration-300"
                        onClick={handleConfirmInspection}
                    >
                        提交并保存 (Submit & Save)
                    </button>
                    <button 
                        type="button"
                        className="bg-[#7f8c8d] text-white border-none py-[10px] px-[15px] rounded-[4px] cursor-pointer text-[16px] m-[5px] hover:bg-[#6c7a7d] transition-colors duration-300"
                        onClick={handleCancelInspection}
                    >
                        取消
                    </button>
                </div>
            </div>
        );
    };

    const renderResultsPage = () => {
        let totalScore = 0;
        let maxTotalScore = 0;
        const completedAreas: { key: string; data: AreaData }[] = [];

        Object.keys(inspectionData.areas).forEach(key => {
            const area = inspectionData.areas[key];
            if (area.completed) {
                totalScore += area.score;
                maxTotalScore += area.maxScore;
                completedAreas.push({ key, data: area });
            }
        });

        const overallPercentage = maxTotalScore > 0 ? (totalScore / maxTotalScore * 100).toFixed(1) : '0';

        return (
            <div id="results-page">
                <div className="bg-[#3498db] text-white p-[15px] rounded-[5px] mb-[20px]">
                    <h2 className="text-center text-xl font-bold">巡店检查结果</h2>
                    <p className="text-center mt-2">检查人: <span>{inspectionData.inspector}</span> | 门店: <span>{inspectionData.shop}</span> | 日期: <span>{inspectionData.date}</span></p>
                </div>

                <div className="text-[18px] font-bold my-[20px] text-center">
                    总分 (Total Score): <span>{totalScore}</span> / <span>{maxTotalScore}</span>
                    (<span>{overallPercentage}</span>%)
                </div>

                <table className="w-full border-collapse my-[20px]">
                    <thead>
                        <tr>
                            <th className="border border-[#ddd] p-[8px] text-left bg-[#3498db] text-white">区域 (Area)</th>
                            <th className="border border-[#ddd] p-[8px] text-left bg-[#3498db] text-white">得分 (Score)</th>
                            <th className="border border-[#ddd] p-[8px] text-left bg-[#3498db] text-white">满分 (Max Score)</th>
                            <th className="border border-[#ddd] p-[8px] text-left bg-[#3498db] text-white">百分比 (%)</th>
                        </tr>
                    </thead>
                    <tbody>
                        {completedAreas.map(({ key, data }, idx) => {
                            const pct = data.maxScore > 0 ? (data.score / data.maxScore * 100).toFixed(1) : '0';
                            return (
                                <tr key={key} className={idx % 2 === 0 ? "bg-[#f2f2f2]" : ""}>
                                    <td className="border border-[#ddd] p-[8px]">{data.name}</td>
                                    <td className="border border-[#ddd] p-[8px]">{data.score}</td>
                                    <td className="border border-[#ddd] p-[8px]">{data.maxScore}</td>
                                    <td className="border border-[#ddd] p-[8px]">{pct}%</td>
                                </tr>
                            );
                        })}
                    </tbody>
                </table>

                <div className="mt-[30px]">
                    <h3 className="text-[#2c3e50] font-bold text-center text-lg mb-2">详细扣分项:</h3>
                    {completedAreas.map(({ key, data }) => {
                        if (data.deductions.length === 0) return null;
                        return (
                            <div key={key}>
                                <h4 className="text-[#2c3e50] font-bold mt-4 mb-2">{data.name}扣分项:</h4>
                                <ul className="list-disc pl-5">
                                    {data.deductions.map((deduction, dIdx) => (
                                        <li key={dIdx} className="text-[#e74c3c] ml-[20px] mb-2">
                                            <strong>{deduction.item}</strong> - {deduction.standard}<br/>
                                            得分: {deduction.score}/{deduction.maxScore}<br/>
                                            扣分原因: {deduction.criteria}
                                        </li>
                                    ))}
                                </ul>
                            </div>
                        );
                    })}
                </div>

                <div className="text-center mt-[20px]">
                    <button 
                        type="button"
                        className="bg-[#27ae60] text-white border-none py-[10px] px-[15px] rounded-[4px] cursor-pointer text-[16px] m-[5px] hover:bg-[#219653] transition-colors duration-300"
                        onClick={() => exportToExcel(inspectionData)}
                    >
                        导出详细报告
                    </button>
                    <button 
                        type="button"
                        className="bg-[#7f8c8d] text-white border-none py-[10px] px-[15px] rounded-[4px] cursor-pointer text-[16px] m-[5px] hover:bg-[#6c7a7d] transition-colors duration-300"
                        onClick={handleBackToAreas}
                    >
                        返回区域选择
                    </button>
                </div>
            </div>
        );
    };

    return (
        <div className="container max-w-[1200px] mx-auto bg-white p-[10px] md:p-[20px] rounded-[8px] shadow-[0_0_10px_rgba(0,0,0,0.1)]">
            {view === 'inspector-info' && renderInspectorInfo()}
            {view === 'area-selection' && renderAreaSelection()}
            {view === 'inspection' && renderInspectionPage()}
            {view === 'results' && renderResultsPage()}
        </div>
    );
};

