                                        </div>
                                    )}
                                </div>
                            );
                        })}
                    </div>
                </div>

                <div className="text-center mt-8">
                    <button 
                        type="button"
                        className="bg-[#7f8c8d] text-white border-none py-[10px] px-[20px] rounded-[4px] cursor-pointer text-[16px] hover:bg-[#6c7a7d] transition-colors duration-300"
                        onClick={handleViewResults}
                    >
                        查看所有结果
                    </button>
                </div>
            </div>
        );
    };

    const renderInspectionPage = () => {
        const area = inspectionData.areas[currentAreaKey];
        if (!area) return null;

        return (
            <div id="inspection-page">
                <div className="bg-[#3498db] text-white p-[15px] rounded-[5px] mb-[20px]">
                    <h2 className="text-center text-xl font-bold">{area.name}</h2>
                    <p className="text-center mt-2">
                        检查人: <span>{inspectionData.inspector}</span> | 
                        被检员工: <span className="font-bold underline text-yellow-300">{currentEmployee}</span> | 
                        日期: <span>{inspectionData.date}</span>
                    </p>
                </div>

                <div className="my-[20px] flex justify-between items-center">
                    <div>
                        <input 
                            type="text" 
                            placeholder="搜索检查项目..." 
                            className="w-[200px] md:w-[300px] p-[8px] border border-[#ddd] rounded-[4px] box-border"
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                        />
                    </div>
                    <div>
                        <button 
                            type="button"
                            className="bg-[#7f8c8d] text-white border-none py-[10px] px-[15px] rounded-[4px] cursor-pointer text-[14px] md:text-[16px] m-[5px] hover:bg-[#6c7a7d] transition-colors duration-300"
                            onClick={handleBackToAreas}
                        >
                            返回选择
                        </button>
                    </div>
                </div>

                <div id="inspection-items-container">
                    {area.items.map((item, itemIdx) => {
                        // Filter logic
                        if (searchTerm && !item.name.toLowerCase().includes(searchTerm.toLowerCase())) {
                            return null;
                        }

                        return (
                            <div key={itemIdx} className="bg-[#f9f9f9] border border-[#ddd] rounded-[5px] p-[15px] mb-[15px]">
                                <h3 className="text-[#2c3e50] text-lg font-bold mb-2 text-center">{item.name}</h3>
                                {item.standards.map((standard, stdIdx) => (
                                    <div key={stdIdx} className="ml-[20px] mb-[10px] p-[10px] bg-[#ecf0f1] rounded-[4px]">
                                        <p className="font-bold mb-[5px]">{standard.name}</p>
                                        <p className="text-[14px] color-[#7f8c8d] mt-[5px] text-gray-500">评分标准: {standard.criteria}</p>
                                        <div className="flex items-center mt-[5px]">
                                            <select 
                                                className="w-[80px] mr-[10px] p-[8px] border border-[#ddd] rounded-[4px]"
                                                value={standard.score}
                                                onChange={(e) => handleUpdateScore(itemIdx, stdIdx, parseInt(e.target.value))}
                                            >
                                                {Array.from({ length: standard.maxScore + 1 }, (_, i) => standard.maxScore - i).map(score => (
                                                    <option key={score} value={score}>{score}分</option>
                                                ))}
                                            </select>
                                            <span> / {standard.maxScore}分</span>
                                        </div>
                                    </div>
                                ))}
                            </div>
                        );
                    })}
                </div>

                <div className="text-[#e74c3c] font-bold my-[15px] p-[10px] bg-[#fdeaea] border-l-4 border-[#e74c3c]">
                    <h3 className="text-center text-[#2c3e50]">红线条款 (Red Line Terms):</h3>
                    {area.redLine.map((line, idx) => (
                        <p key={idx}>{line}</p>
                    ))}
                </div>

                <div className="mt-[30px] pt-[20px] border-t border-dashed border-[#ccc]">
                    <p>巡店人签名 (Inspector Signature): _________________________</p>
                    <p className="mt-2">被检员工确认 (Employee Signature): _________________________ ({currentEmployee})</p>
                </div>

                <div className="text-center mt-[20px]">
                    <button 
                        type="button"
                        className="bg-[#27ae60] text-white border-none py-[10px] px-[15px] rounded-[4px] cursor-pointer text-[16px] m-[5px] hover:bg-[#219653] transition-colors duration-300"
                        onClick={handleConfirmInspection}
                    >
                        提交并保存 (Submit & Save)
                    </button>
                    <button 
                        type="button"
                        className="bg-[#7f8c8d] text-white border-none py-[10px] px-[15px] rounded-[4px] cursor-pointer text-[16px] m-[5px] hover:bg-[#6c7a7d] transition-colors duration-300"
                        onClick={handleCancelInspection}
                    >
                        取消
                    </button>
                </div>
            </div>
        );
    };

    const renderResultsPage = () => {
        let totalScore = 0;
        let maxTotalScore = 0;
        const completedAreas: { key: string; data: AreaData }[] = [];

        Object.keys(inspectionData.areas).forEach(key => {
            const area = inspectionData.areas[key];
            if (area.completed) {
                totalScore += area.score;
                maxTotalScore += area.maxScore;
                completedAreas.push({ key, data: area });
            }
        });

        const overallPercentage = maxTotalScore > 0 ? (totalScore / maxTotalScore * 100).toFixed(1) : '0';

        return (
            <div id="results-page">
                <div className="bg-[#3498db] text-white p-[15px] rounded-[5px] mb-[20px]">
                    <h2 className="text-center text-xl font-bold">巡店检查结果</h2>
                    <p className="text-center mt-2">检查人: <span>{inspectionData.inspector}</span> | 门店: <span>{inspectionData.shop}</span> | 日期: <span>{inspectionData.date}</span></p>
                </div>

                <div className="text-[18px] font-bold my-[20px] text-center">
                    总分 (Total Score): <span>{totalScore}</span> / <span>{maxTotalScore}</span>
                    (<span>{overallPercentage}</span>%)
                </div>

                <table className="w-full border-collapse my-[20px]">
                    <thead>
                        <tr>
                            <th className="border border-[#ddd] p-[8px] text-left bg-[#3498db] text-white">区域 (Area)</th>
                            <th className="border border-[#ddd] p-[8px] text-left bg-[#3498db] text-white">员工 (Employee)</th>
                            <th className="border border-[#ddd] p-[8px] text-left bg-[#3498db] text-white">得分 (Score)</th>
                            <th className="border border-[#ddd] p-[8px] text-left bg-[#3498db] text-white">满分 (Max Score)</th>
                            <th className="border border-[#ddd] p-[8px] text-left bg-[#3498db] text-white">百分比 (%)</th>
                        </tr>
                    </thead>
                    <tbody>
                        {completedAreas.map(({ key, data }, idx) => {
                            const pct = data.maxScore > 0 ? (data.score / data.maxScore * 100).toFixed(1) : '0';
                            return (
                                <tr key={key} className={idx % 2 === 0 ? "bg-[#f2f2f2]" : ""}>
                                    <td className="border border-[#ddd] p-[8px]">{data.name}</td>
                                    <td className="border border-[#ddd] p-[8px] font-bold text-blue-600">{data.employee || '-'}</td>
                                    <td className="border border-[#ddd] p-[8px]">{data.score}</td>
                                    <td className="border border-[#ddd] p-[8px]">{data.maxScore}</td>
                                    <td className="border border-[#ddd] p-[8px]">{pct}%</td>
                                </tr>
                            );
                        })}
                    </tbody>
                </table>

                <div className="mt-[30px]">
                    <h3 className="text-[#2c3e50] font-bold text-center text-lg mb-2">详细扣分项:</h3>
                    {completedAreas.map(({ key, data }) => {
                        if (data.deductions.length === 0) return null;
                        return (
                            <div key={key}>
                                <h4 className="text-[#2c3e50] font-bold mt-4 mb-2">{data.name} ({data.employee}) 扣分项:</h4>
                                <ul className="list-disc pl-5">
                                    {data.deductions.map((deduction, dIdx) => (
                                        <li key={dIdx} className="text-[#e74c3c] ml-[20px] mb-2">
                                            <strong>{deduction.item}</strong> - {deduction.standard}<br/>
                                            得分: {deduction.score}/{deduction.maxScore}<br/>
                                            扣分原因: {deduction.criteria}
                                        </li>
                                    ))}
                                </ul>
                            </div>
                        );
                    })}
                </div>

                <div className="text-center mt-[20px]">
                    <button 
                        type="button"
                        className="bg-[#27ae60] text-white border-none py-[10px] px-[15px] rounded-[4px] cursor-pointer text-[16px] m-[5px] hover:bg-[#219653] transition-colors duration-300"
                        onClick={() => exportToExcel(inspectionData)}
                    >
                        导出详细报告
                    </button>
                    <button 
                        type="button"
                        className="bg-[#7f8c8d] text-white border-none py-[10px] px-[15px] rounded-[4px] cursor-pointer text-[16px] m-[5px] hover:bg-[#6c7a7d] transition-colors duration-300"
                        onClick={handleBackToAreas}
                    >
                        返回区域选择
                    </button>
                </div>
            </div>
        );
    };

    return (
        <div className="container max-w-[1200px] mx-auto bg-white p-[10px] md:p-[20px] rounded-[8px] shadow-[0_0_10px_rgba(0,0,0,0.1)]">
            {view === 'inspector-info' && renderInspectorInfo()}
            {view === 'management' && renderManagement()}
            {view === 'area-selection' && renderAreaSelection()}
            {view === 'inspection' && renderInspectionPage()}
            {view === 'results' && renderResultsPage()}
        </div>
    );
};

export default App;

import { InspectionData } from "../types";

export function exportToExcel(inspectionData: InspectionData) {
    let totalScore = 0;
    let maxTotalScore = 0;

    Object.keys(inspectionData.areas).forEach(key => {
        const area = inspectionData.areas[key];
        if (area.completed) {
            totalScore += area.score;
            maxTotalScore += area.maxScore;
        }
    });

    const percentage = maxTotalScore > 0 ? (totalScore / maxTotalScore * 100).toFixed(1) : "0.0";

    // 创建HTML表格内容
    let html = `
        <html xmlns:o="urn:schemas-microsoft-com:office:office" xmlns:x="urn:schemas-microsoft-com:office:excel" xmlns="http://www.w3.org/TR/REC-html40">
        <head>
            <meta charset="UTF-8">
            <title>巡店检查报告</title>
            <!--[if gte mso 9]>
            <xml>
                <x:ExcelWorkbook>
                    <x:ExcelWorksheets>
                        <x:ExcelWorksheet>
                            <x:Name>巡店检查报告</x:Name>
                            <x:WorksheetOptions>
                                <x:DisplayGridlines/>
                            </x:WorksheetOptions>
                        </x:ExcelWorksheet>
                    </x:ExcelWorksheets>
                </x:ExcelWorkbook>
            </xml>
            <![endif]-->
            <style>
                table {
                    border-collapse: collapse;
                    width: 100%;
                }
                th, td {
                    border: 1px solid #ddd;
                    padding: 8px;
                    text-align: left;
                }
                th {
                    background-color: #3498db;
                    color: white;
                }
                .deduction-item {
                    color: #e74c3c;
                    margin-left: 20px;
                }
            </style>
        </head>
        <body>
            <h1>巡店检查报告</h1>
            <p>检查人: ${inspectionData.inspector}</p>
            <p>门店名称: ${inspectionData.shop}</p>
            <p>检查日期: ${inspectionData.date}</p>

            <h2>总分: ${totalScore} / ${maxTotalScore} (${percentage}%)</h2>

            <h3>各区域得分汇总</h3>
            <table>
                <tr>
                    <th>区域</th>
                    <th>员工</th>
                    <th>得分</th>
                    <th>满分</th>
                    <th>百分比</th>
                </tr>
    `;

    // 添加各区域得分
    for (const areaKey in inspectionData.areas) {
        const area = inspectionData.areas[areaKey];
        if (area.completed) {
            let areaName = area.name || "";
            if (!areaName) {
                switch(areaKey) {
                    case 'vegetables': areaName = '蔬果区'; break;
                    case 'grocery': areaName = '食百区'; break;
                    case 'seafood': areaName = '水产区'; break;
                    case 'meat': areaName = '肉品区'; break;
                    case 'deli': areaName = '熟食区'; break;
                    case 'cashier': areaName = '收银区域'; break;
                }
            }

            const areaPercentage = area.maxScore > 0 ? (area.score / area.maxScore * 100).toFixed(1) : "0.0";

            html += `
                <tr>
                    <td>${areaName}</td>
                    <td>${area.employee || '-'}</td>
                    <td>${area.score}</td>
                    <td>${area.maxScore}</td>
                    <td>${areaPercentage}%</td>
                </tr>
            `;
        }
    }

    html += `
            </table>

            <h3>详细扣分项</h3>
    `;

    // 添加详细扣分项
    for (const areaKey in inspectionData.areas) {
        const area = inspectionData.areas[areaKey];
        if (area.completed && area.deductions.length > 0) {
            let areaName = area.name || "";
            // Fallback for names if not provided in data object directly
             if (!areaName) {
                switch(areaKey) {
                    case 'vegetables': areaName = '蔬果区'; break;
                    case 'grocery': areaName = '食百区'; break;
                    case 'seafood': areaName = '水产区'; break;
                    case 'meat': areaName = '肉品区'; break;
                    case 'deli': areaName = '熟食区'; break;
                    case 'cashier': areaName = '收银区域'; break;
                }
            }

            html += `<h4>${areaName} (员工: ${area.employee || '未记录'})</h4><table>`;
            html += `
                <tr>
                    <th>检查项目</th>
                    <th>检查标准</th>
                    <th>得分</th>
                    <th>满分</th>
                    <th>扣分原因</th>
                </tr>
            `;

            area.deductions.forEach(deduction => {
                html += `
                    <tr>
                        <td>${deduction.item}</td>
                        <td>${deduction.standard}</td>
                        <td>${deduction.score}</td>
                        <td>${deduction.maxScore}</td>
                        <td>${deduction.criteria}</td>
                    </tr>
                `;
            });

            html += `</table>`;
        }
    }

    // 添加红线条款
    html += `<h3>红线条款</h3><ul>`;
    for (const areaKey in inspectionData.areas) {
        const area = inspectionData.areas[areaKey];
        if (area.completed) {
            let areaName = area.name || "";
             if (!areaName) {
                switch(areaKey) {
                    case 'vegetables': areaName = '蔬果区'; break;
                    case 'grocery': areaName = '食百区'; break;
                    case 'seafood': areaName = '水产区'; break;
                    case 'meat': areaName = '肉品区'; break;
                    case 'deli': areaName = '熟食区'; break;
                    case 'cashier': areaName = '收银区域'; break;
                }
            }

            html += `<li><strong>${areaName} (${area.employee}):</strong><ul>`;
            area.redLine.forEach(item => {
                html += `<li>${item}</li>`;
            });
            html += `</ul></li>`;
        }
    }
    html += `</ul>`;

    html += `
        </body>
        </html>
    `;

    // 创建Blob对象
    const blob = new Blob([html], { type: 'application/vnd.ms-excel' });

    // 创建下载链接
    const a = document.createElement('a');
    a.href = URL.createObjectURL(blob);
    a.download = `巡店检查报告_${inspectionData.shop}_${inspectionData.date.replace(/[: ]/g, '-')}.xls`;

    // 触发下载
    document.body.appendChild(a);
    a.click();

    // 清理
    setTimeout(() => {
        document.body.removeChild(a);
        URL.revokeObjectURL(a.href);
    }, 100);
}

export interface Standard {
    name: string;
    score: number;
    maxScore: number;
    criteria: string;
}

export interface Item {
    name: string;
    standards: Standard[];
}

export interface Deduction {
    item: string;
    standard: string;
    score: number;
    maxScore: number;
    criteria: string;
}

export interface AreaData {
    name?: string; // For display purposes
    items: Item[];
    score: number;
    maxScore: number;
    completed: boolean;
    deductions: Deduction[];
    redLine: string[];
    employee?: string; // The employee being inspected
}

// New Interface for stored records
export interface InspectionRecord extends AreaData {
    id: string; // Unique ID for the record
    areaKey: string; // e.g., 'vegetables'
    timestamp: string;
}

export interface Areas {
    [key: string]: AreaData;
    vegetables: AreaData;
    grocery: AreaData;
    seafood: AreaData;
    meat: AreaData;
    deli: AreaData;
    cashier: AreaData;
}

export interface InspectionData {
    inspector: string;
    shop: string;
    date: string;
    areas: Areas; // Represents the "Current Working State" of the form
    records: InspectionRecord[]; // Added: List of completed inspections
}

export type EmployeeConfig = {
    [key: string]: string[];
}

export type ViewState = 'inspector-info' | 'area-selection' | 'inspection' | 'results' | 'management';

import React, { useState, useEffect } from 'react';
import { InspectionData, ViewState, Areas, AreaData, Deduction, EmployeeConfig, InspectionRecord } from './types';
import { INITIAL_AREAS, INITIAL_EMPLOYEES } from './data';
import { exportToExcel } from './utils/excelExport';

const App: React.FC = () => {
    // Application State
    const [inspectionData, setInspectionData] = useState<InspectionData>(() => ({
        inspector: '',
        shop: '',
        date: '',
        areas: JSON.parse(JSON.stringify(INITIAL_AREAS)), // Deep copy to ensure fresh state
        records: [] // Store completed records here
    }));

    const [employees, setEmployees] = useState<EmployeeConfig>(INITIAL_EMPLOYEES);

    const [view, setView] = useState<ViewState>('inspector-info');
    const [currentAreaKey, setCurrentAreaKey] = useState<string>('');
    const [currentEmployee, setCurrentEmployee] = useState<string>(''); // Currently selected employee for inspection
    const [searchTerm, setSearchTerm] = useState<string>('');

    // For Area Selection View
    const [selectionAreaKey, setSelectionAreaKey] = useState<string>('');
    const [selectionEmployee, setSelectionEmployee] = useState<string>('');

    // For Management View
    const [manageAreaKey, setManageAreaKey] = useState<string>('vegetables');
    const [newEmployeeName, setNewEmployeeName] = useState<string>('');

    // Initialize Date
    useEffect(() => {
        const now = new Date();
        const formattedDate = now.getFullYear() + '-' + 
                             String(now.getMonth() + 1).padStart(2, '0') + '-' + 
                             String(now.getDate()).padStart(2, '0') + ' ' + 
                             String(now.getHours()).padStart(2, '0') + ':' + 
                             String(now.getMinutes()).padStart(2, '0');

        setInspectionData(prev => ({ ...prev, date: formattedDate }));
    }, []);

    // --- Actions ---

    const handleStartInspection = (inspector: string, shop: string) => {
        if (!inspector || !shop) {
            alert('请填写检查人姓名和门店名称');
            return;
        }
        setInspectionData(prev => ({ ...prev, inspector, shop }));
        setView('area-selection');
    };

    const handleEnterInspection = () => {
        if (!selectionAreaKey) {
            alert("请选择一个区域");
            return;
        }
        if (!selectionEmployee) {
            alert("请选择该区域的员工");
            return;
        }

        // Update current context
        setCurrentAreaKey(selectionAreaKey);
        setCurrentEmployee(selectionEmployee);

        // RESET Logic: When starting a new inspection for a specific employee, 
        // we must load a fresh copy of that area's data (scores reset to default)
        // so previous inspections don't interfere.
        setInspectionData(prev => {
            const newAreas = { ...prev.areas };
            // Get fresh data from INITIAL_AREAS
            const freshArea = JSON.parse(JSON.stringify(INITIAL_AREAS[selectionAreaKey]));

            // Assign the selected employee to this fresh instance
            freshArea.employee = selectionEmployee;

            newAreas[selectionAreaKey] = freshArea;

            return { ...prev, areas: newAreas };
        });

        setSearchTerm('');
        setView('inspection');
    };

    const handleViewResults = () => {
        setView('results');
    };

    const handleBackToAreas = () => {
        // Reset selection state
        setSelectionAreaKey('');
        setSelectionEmployee('');
        setView('area-selection');
    };

    const handleUpdateScore = (itemIndex: number, standardIndex: number, newScore: number) => {
        setInspectionData(prev => {
            // Create a deep enough copy to avoid direct mutation
            const newAreas = { ...prev.areas };
            const newArea = { ...newAreas[currentAreaKey] };

            // Deep copy items array to ensure React detects the change
            newArea.items = newArea.items.map((item, idx) => {
                if (idx !== itemIndex) return item;
                return {
                    ...item,
                    standards: item.standards.map((std, sIdx) => {
                        if (sIdx !== standardIndex) return std;
                        return { ...std, score: newScore };
                    })
                };
            });

            newAreas[currentAreaKey] = newArea;
            return { ...prev, areas: newAreas };
        });
    };

    const handleConfirmInspection = () => {
        if (!currentAreaKey) return;

        const currentArea = inspectionData.areas[currentAreaKey];
        if (!currentArea) return;

        // --- Calculation Logic ---
        let totalScore = 0;
        let maxScore = 0;
        const deductions: Deduction[] = [];

        currentArea.items.forEach(item => {
            item.standards.forEach(standard => {
                totalScore += standard.score;
                maxScore += standard.maxScore;

                if (standard.score < standard.maxScore) {
                    deductions.push({
                        item: item.name,
                        standard: standard.name,
                        score: standard.score,
                        maxScore: standard.maxScore,
                        criteria: standard.criteria
                    });
                }
            });
        });

        // --- State Update ---
        setInspectionData(prev => {
            // Create the finished record
            const newRecord: InspectionRecord = {
                ...currentArea,
                score: totalScore,
                maxScore: maxScore,
                completed: true,
                deductions: deductions,
                employee: currentEmployee,
                areaKey: currentAreaKey,
                id: Date.now().toString() // Simple ID
            };

            // Add to records list
            // We do NOT modify prev.areas in a way that blocks future inspections.
            // prev.areas is just the "working draft".

            return {
                ...prev,
                records: [...prev.records, newRecord]
            };
        });

        alert("提交成功！(Submitted Successfully)");
        handleBackToAreas();
    };

    const handleCancelInspection = () => {
         if (window.confirm('确定要取消当前检查吗？未保存的评分将丢失。')) {
            handleBackToAreas();
        }
    };

    // Management Actions
    const handleAddEmployee = () => {
        if (!newEmployeeName.trim()) return;
        setEmployees(prev => ({
            ...prev,
            [manageAreaKey]: [...(prev[manageAreaKey] || []), newEmployeeName.trim()]
        }));
        setNewEmployeeName('');
    };

    const handleDeleteEmployee = (nameToDelete: string) => {
        if (window.confirm(`确定要删除员工 ${nameToDelete} 吗？`)) {
            setEmployees(prev => ({
                ...prev,
                [manageAreaKey]: prev[manageAreaKey].filter(name => name !== nameToDelete)
            }));
        }
    };

    const handleDeleteRecord = (recordId: string) => {
        if(window.confirm("确定要删除这条检查记录吗？")) {
            setInspectionData(prev => ({
                ...prev,
                records: prev.records.filter(r => r.id !== recordId)
            }));
        }
    }

    // --- Renderers ---

    const renderInspectorInfo = () => (
        <div id="inspector-info-page">
            <div className="bg-[#3498db] text-white p-[15px] rounded-[5px] mb-[20px] relative">
                <h1 className="text-center text-2xl font-bold">超市巡店检查评分系统</h1>
                <button 
                    onClick={() => setView('management')}
                    className="absolute right-[10px] top-[15px] bg-transparent border border-white text-white px-2 py-1 rounded text-sm hover:bg-white hover:text-[#3498db] transition"
                >
                    管理后台
                </button>
            </div>
            <div className="mb-[15px]">
                <label className="block mb-[5px] font-bold">检查人姓名 (Inspector Name):</label>
                <input 
                    type="text" 
                    className="w-full p-[8px] border border-[#ddd] rounded-[4px] box-border"
                    value={inspectionData.inspector}
                    onChange={(e) => setInspectionData(prev => ({...prev, inspector: e.target.value}))}
                    required 
                />
            </div>
            <div className="mb-[15px]">
                <label className="block mb-[5px] font-bold">门店名称 (Shop Name):</label>
                <input 
                    type="text" 
                    className="w-full p-[8px] border border-[#ddd] rounded-[4px] box-border"
                    value={inspectionData.shop}
                    onChange={(e) => setInspectionData(prev => ({...prev, shop: e.target.value}))}
                    required 
                />
            </div>
            <div className="mb-[15px]">
                <label className="block mb-[5px] font-bold">检查日期 (Inspection Date):</label>
                <input 
                    type="text" 
                    className="w-full p-[8px] border border-[#ddd] rounded-[4px] box-border bg-gray-100"
                    value={inspectionData.date}
                    readOnly 
                />
            </div>
            <button 
                type="button"
                className="bg-[#27ae60] text-white border-none py-[10px] px-[15px] rounded-[4px] cursor-pointer text-[16px] m-[5px] hover:bg-[#219653] transition-colors duration-300 w-full"
                onClick={() => handleStartInspection(inspectionData.inspector, inspectionData.shop)}
            >
                开始检查
            </button>
        </div>
    );

    const renderManagement = () => (
        <div id="management-page">
            <div className="bg-[#3498db] text-white p-[15px] rounded-[5px] mb-[20px] flex justify-between items-center">
                <h2 className="text-xl font-bold">人员管理后台</h2>
                <button 
                    onClick={() => setView('inspector-info')}
                    className="bg-transparent border border-white text-white px-3 py-1 rounded hover:bg-white hover:text-[#3498db]"
                >
                    返回首页
                </button>
            </div>

            <div className="flex flex-col md:flex-row gap-4">
                <div className="w-full md:w-1/3 bg-gray-50 p-4 rounded border">
                    <h3 className="font-bold mb-3">选择区域</h3>
                    <div className="flex flex-col gap-2">
                        {[
                            { key: 'vegetables', label: '蔬果区' },
                            { key: 'grocery', label: '食百区' },
                            { key: 'seafood', label: '水产区' },
                            { key: 'meat', label: '肉品区' },
                            { key: 'deli', label: '熟食区' },
                            { key: 'cashier', label: '收银区域' }
                        ].map(area => (
                            <button
                                key={area.key}
                                onClick={() => setManageAreaKey(area.key)}
                                className={`text-left p-3 rounded ${manageAreaKey === area.key ? 'bg-[#3498db] text-white' : 'bg-white hover:bg-gray-100'}`}
                            >
                                {area.label}
                            </button>
                        ))}
                    </div>
                </div>

                <div className="w-full md:w-2/3 bg-white p-4 rounded border">
                    <h3 className="font-bold mb-3">
                        管理 {manageAreaKey === 'vegetables' ? '蔬果区' : 
                              manageAreaKey === 'grocery' ? '食百区' :
                              manageAreaKey === 'seafood' ? '水产区' :
                              manageAreaKey === 'meat' ? '肉品区' :
                              manageAreaKey === 'deli' ? '熟食区' : '收银区域'} 员工
                    </h3>

                    <div className="flex gap-2 mb-4">
                        <input 
                            type="text" 
                            className="flex-1 p-2 border rounded"
                            placeholder="输入员工姓名"
                            value={newEmployeeName}
                            onChange={(e) => setNewEmployeeName(e.target.value)}
                        />
                        <button 
                            onClick={handleAddEmployee}
                            className="bg-[#27ae60] text-white px-4 py-2 rounded hover:bg-[#219653]"
                        >
                            添加
                        </button>
                    </div>

                    <div className="space-y-2">
                        {employees[manageAreaKey]?.map((name, idx) => (
                            <div key={idx} className="flex justify-between items-center p-3 bg-gray-50 rounded border">
                                <span>{name}</span>
                                <button 
                                    onClick={() => handleDeleteEmployee(name)}
                                    className="text-red-500 hover:text-red-700 font-bold"
                                >
                                    删除
                                </button>
                            </div>
                        ))}
                        {(!employees[manageAreaKey] || employees[manageAreaKey].length === 0) && (
                            <p className="text-gray-400 text-center py-4">暂无员工，请添加</p>
                        )}
                    </div>
                </div>
            </div>
        </div>
    );

    const renderAreaSelection = () => {
        const areaOptions = [
            { key: 'vegetables', label: '蔬果区', sub: 'Vegetables & Fruits' },
            { key: 'grocery', label: '食百区', sub: 'Food & Grocery' },
            { key: 'seafood', label: '水产区', sub: 'SeaFood' },
            { key: 'meat', label: '肉品区', sub: 'Meat' },
            { key: 'deli', label: '熟食区', sub: 'Deli' },
            { key: 'cashier', label: '收银区域', sub: 'Cashier' }
        ];

        return (
            <div id="area-selection-page">
                <div className="bg-[#3498db] text-white p-[15px] rounded-[5px] mb-[20px]">
                    <h2 className="text-center text-xl font-bold">请选择检查区域和员工</h2>
                    <p className="text-center mt-2">检查人: <span>{inspectionData.inspector}</span> | 门店: <span>{inspectionData.shop}</span> | 日期: <span>{inspectionData.date}</span></p>
                </div>

                <div className="max-w-md mx-auto bg-white p-6 rounded shadow-sm border border-gray-200">
                    <div className="mb-4">
                        <label className="block mb-2 font-bold text-gray-700">1. 选择区域 (Select Area)</label>
                        <select 
                            className="w-full p-3 border border-gray-300 rounded bg-white"
                            value={selectionAreaKey}
                            onChange={(e) => {
                                setSelectionAreaKey(e.target.value);
                                setSelectionEmployee(''); // Reset employee when area changes
                            }}
                        >
                            <option value="">-- 请选择 --</option>
                            {areaOptions.map(opt => {
                                // Count how many inspections done for this area
                                const count = inspectionData.records.filter(r => r.areaKey === opt.key).length;
                                return (
                                    <option key={opt.key} value={opt.key}>
                                        {opt.label} {count > 0 ? `(已检: ${count}人)` : ''}
                                    </option>
                                );
                            })}
                        </select>
                    </div>

                    <div className="mb-6">
                        <label className="block mb-2 font-bold text-gray-700">2. 选择员工 (Select Employee)</label>
                        <select 
                            className="w-full p-3 border border-gray-300 rounded bg-white"
                            value={selectionEmployee}
                            onChange={(e) => setSelectionEmployee(e.target.value)}
                            disabled={!selectionAreaKey}
                        >
                            <option value="">-- 请选择 --</option>
                            {selectionAreaKey && employees[selectionAreaKey]?.map((name, idx) => (
                                <option key={idx} value={name}>{name}</option>
                            ))}
                        </select>
                        {!selectionAreaKey && <p className="text-sm text-gray-500 mt-1">请先选择区域</p>}
                        {selectionAreaKey && (!employees[selectionAreaKey] || employees[selectionAreaKey].length === 0) && (
                            <p className="text-sm text-red-500 mt-1">该区域暂无员工，请联系管理员添加</p>
                        )}
                    </div>

                    <button 
                        type="button"
                        disabled={!selectionAreaKey || !selectionEmployee}
                        className={`w-full py-3 px-4 rounded font-bold text-white transition-colors duration-300 ${(!selectionAreaKey || !selectionEmployee) ? 'bg-gray-400 cursor-not-allowed' : 'bg-[#27ae60] hover:bg-[#219653] cursor-pointer'}`}
                        onClick={handleEnterInspection}
                    >
                        开始检查
                    </button>
                </div>

                <div className="mt-8 border-t pt-6">
                    <h3 className="text-lg font-bold text-gray-700 mb-4 text-center">当前已完成检查列表</h3>
                    {inspectionData.records.length === 0 ? (
                         <p className="text-center text-gray-400">暂无完成的检查记录</p>
                    ) : (
                        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                            {inspectionData.records.map((record) => (
                                <div key={record.id} className="p-4 rounded border bg-green-50 border-green-200 relative">
                                    <div className="font-bold">{record.name}</div>
                                    <div className="text-sm mt-1 text-gray-600">
                                        员工: <strong className="text-blue-600">{record.employee}</strong>
                                    </div>
                                    <div className="text-sm mt-1">
                                        得分: {record.score} / {record.maxScore}
                                    </div>
                                    <button 
                                        onClick={() => handleDeleteRecord(record.id)}
                                        className="absolute top-2 right-2 text-red-500 hover:text-red-700 text-sm"
                                    >
                                        删除
                                    </button>
                                </div>
                            ))}
                        </div>
                    )}
                </div>

                <div className="text-center mt-8">
                    <button 
                        type="button"
                        className="bg-[#7f8c8d] text-white border-none py-[10px] px-[20px] rounded-[4px] cursor-pointer text-[16px] hover:bg-[#6c7a7d] transition-colors duration-300"
                        onClick={handleViewResults}
                        disabled={inspectionData.records.length === 0}
                    >
                        查看结果汇总 & 导出
                    </button>
                </div>
            </div>
        );
    };

    const renderInspectionPage = () => {
        const area = inspectionData.areas[currentAreaKey];
        if (!area) return null;

        return (
            <div id="inspection-page">
                <div className="bg-[#3498db] text-white p-[15px] rounded-[5px] mb-[20px]">
                    <h2 className="text-center text-xl font-bold">{area.name}</h2>
                    <p className="text-center mt-2">
                        检查人: <span>{inspectionData.inspector}</span> | 
                        被检员工: <span className="font-bold underline text-yellow-300">{currentEmployee}</span> | 
                        日期: <span>{inspectionData.date}</span>
                    </p>
                </div>

                <div className="my-[20px] flex justify-between items-center">
                    <div>
                        <input 
                            type="text" 
                            placeholder="搜索检查项目..." 
                            className="w-[200px] md:w-[300px] p-[8px] border border-[#ddd] rounded-[4px] box-border"
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                        />
                    </div>
                    <div>
                        <button 
                            type="button"
                            className="bg-[#7f8c8d] text-white border-none py-[10px] px-[15px] rounded-[4px] cursor-pointer text-[14px] md:text-[16px] m-[5px] hover:bg-[#6c7a7d] transition-colors duration-300"
                            onClick={handleBackToAreas}
                        >
                            放弃并返回
                        </button>
                    </div>
                </div>

                <div id="inspection-items-container">
                    {area.items.map((item, itemIdx) => {
                        // Filter logic
                        if (searchTerm && !item.name.toLowerCase().includes(searchTerm.toLowerCase())) {
                            return null;
                        }

                        return (
                            <div key={itemIdx} className="bg-[#f9f9f9] border border-[#ddd] rounded-[5px] p-[15px] mb-[15px]">
                                <h3 className="text-[#2c3e50] text-lg font-bold mb-2 text-center">{item.name}</h3>
                                {item.standards.map((standard, stdIdx) => (
                                    <div key={stdIdx} className="ml-[20px] mb-[10px] p-[10px] bg-[#ecf0f1] rounded-[4px]">
                                        <p className="font-bold mb-[5px]">{standard.name}</p>
                                        <p className="text-[14px] color-[#7f8c8d] mt-[5px] text-gray-500">评分标准: {standard.criteria}</p>
                                        <div className="flex items-center mt-[5px]">
                                            <select 
                                                className="w-[80px] mr-[10px] p-[8px] border border-[#ddd] rounded-[4px]"
                                                value={standard.score}
                                                onChange={(e) => handleUpdateScore(itemIdx, stdIdx, parseInt(e.target.value))}
                                            >
                                                {Array.from({ length: standard.maxScore + 1 }, (_, i) => standard.maxScore - i).map(score => (
                                                    <option key={score} value={score}>{score}分</option>
                                                ))}
                                            </select>
                                            <span> / {standard.maxScore}分</span>
                                        </div>
                                    </div>
                                ))}
                            </div>
                        );
                    })}
                </div>

                <div className="text-[#e74c3c] font-bold my-[15px] p-[10px] bg-[#fdeaea] border-l-4 border-[#e74c3c]">
                    <h3 className="text-center text-[#2c3e50]">红线条款 (Red Line Terms):</h3>
                    {area.redLine.map((line, idx) => (
                        <p key={idx}>{line}</p>
                    ))}
                </div>

                <div className="mt-[30px] pt-[20px] border-t border-dashed border-[#ccc]">
                    <p>巡店人签名 (Inspector Signature): _________________________</p>
                    <p className="mt-2">被检员工确认 (Employee Signature): _________________________ ({currentEmployee})</p>
                </div>

                <div className="text-center mt-[20px]">
                    <button 
                        type="button"
                        className="bg-[#27ae60] text-white border-none py-[10px] px-[15px] rounded-[4px] cursor-pointer text-[16px] m-[5px] hover:bg-[#219653] transition-colors duration-300"
                        onClick={handleConfirmInspection}
                    >
                        提交并保存 (Submit & Save)
                    </button>
                    <button 
                        type="button"
                        className="bg-[#7f8c8d] text-white border-none py-[10px] px-[15px] rounded-[4px] cursor-pointer text-[16px] m-[5px] hover:bg-[#6c7a7d] transition-colors duration-300"
                        onClick={handleCancelInspection}
                    >
                        取消
                    </button>
                </div>
            </div>
        );
    };

    const renderResultsPage = () => {
        let totalScore = 0;
        let maxTotalScore = 0;

        // Use the records array for calculation
        const records = inspectionData.records;

        records.forEach(record => {
            totalScore += record.score;
            maxTotalScore += record.maxScore;
        });

        const overallPercentage = maxTotalScore > 0 ? (totalScore / maxTotalScore * 100).toFixed(1) : '0';

        return (
            <div id="results-page">
                <div className="bg-[#3498db] text-white p-[15px] rounded-[5px] mb-[20px]">
                    <h2 className="text-center text-xl font-bold">巡店检查结果汇总</h2>
                    <p className="text-center mt-2">检查人: <span>{inspectionData.inspector}</span> | 门店: <span>{inspectionData.shop}</span> | 日期: <span>{inspectionData.date}</span></p>
                </div>

                <div className="text-[18px] font-bold my-[20px] text-center">
                    共检查: {records.length} 人次 | 总分: <span>{totalScore}</span> / <span>{maxTotalScore}</span>
                    (<span>{overallPercentage}</span>%)
                </div>

                <table className="w-full border-collapse my-[20px]">
                    <thead>
                        <tr>
                            <th className="border border-[#ddd] p-[8px] text-left bg-[#3498db] text-white">区域 (Area)</th>
                            <th className="border border-[#ddd] p-[8px] text-left bg-[#3498db] text-white">员工 (Employee)</th>
                            <th className="border border-[#ddd] p-[8px] text-left bg-[#3498db] text-white">得分 (Score)</th>
                            <th className="border border-[#ddd] p-[8px] text-left bg-[#3498db] text-white">满分 (Max Score)</th>
                            <th className="border border-[#ddd] p-[8px] text-left bg-[#3498db] text-white">百分比 (%)</th>
                        </tr>
                    </thead>
                    <tbody>
                        {records.map((data, idx) => {
                            const pct = data.maxScore > 0 ? (data.score / data.maxScore * 100).toFixed(1) : '0';
                            return (
                                <tr key={idx} className={idx % 2 === 0 ? "bg-[#f2f2f2]" : ""}>
                                    <td className="border border-[#ddd] p-[8px]">{data.name}</td>
                                    <td className="border border-[#ddd] p-[8px] font-bold text-blue-600">{data.employee || '-'}</td>
                                    <td className="border border-[#ddd] p-[8px]">{data.score}</td>
                                    <td className="border border-[#ddd] p-[8px]">{data.maxScore}</td>
                                    <td className="border border-[#ddd] p-[8px]">{pct}%</td>
                                </tr>
                            );
                        })}
                    </tbody>
                </table>

                <div className="mt-[30px]">
                    <h3 className="text-[#2c3e50] font-bold text-center text-lg mb-2">详细扣分项:</h3>
                    {records.map((data, idx) => {
                        if (data.deductions.length === 0) return null;
                        return (
                            <div key={idx} className="mb-6 border-b pb-4">
                                <h4 className="text-[#2c3e50] font-bold mt-4 mb-2">{data.name} ({data.employee}) 扣分项:</h4>
                                <ul className="list-disc pl-5">
                                    {data.deductions.map((deduction, dIdx) => (
                                        <li key={dIdx} className="text-[#e74c3c] ml-[20px] mb-2">
                                            <strong>{deduction.item}</strong> - {deduction.standard}<br/>
                                            得分: {deduction.score}/{deduction.maxScore}<br/>
                                            扣分原因: {deduction.criteria}
                                        </li>
                                    ))}
                                </ul>
                            </div>
                        );
                    })}
                </div>

                <div className="text-center mt-[20px]">
                    <button 
                        type="button"
                        className="bg-[#27ae60] text-white border-none py-[10px] px-[15px] rounded-[4px] cursor-pointer text-[16px] m-[5px] hover:bg-[#219653] transition-colors duration-300"
                        onClick={() => exportToExcel(inspectionData)}
                    >
                        导出详细报告 (Excel)
                    </button>
                    <button 
                        type="button"
                        className="bg-[#7f8c8d] text-white border-none py-[10px] px-[15px] rounded-[4px] cursor-pointer text-[16px] m-[5px] hover:bg-[#6c7a7d] transition-colors duration-300"
                        onClick={handleBackToAreas}
                    >
                        返回继续检查
                    </button>
                </div>
            </div>
        );
    };

    return (
        <div className="container max-w-[1200px] mx-auto bg-white p-[10px] md:p-[20px] rounded-[8px] shadow-[0_0_10px_rgba(0,0,0,0.1)]">
            {view === 'inspector-info' && renderInspectorInfo()}
            {view === 'management' && renderManagement()}
            {view === 'area-selection' && renderAreaSelection()}
            {view === 'inspection' && renderInspectionPage()}
            {view === 'results' && renderResultsPage()}
        </div>
    );
};

export default App;

import { InspectionData } from "../types";

export function exportToExcel(inspectionData: InspectionData) {
    let totalScore = 0;
    let maxTotalScore = 0;

    // Use records instead of areas
    const records = inspectionData.records;

    records.forEach(record => {
        totalScore += record.score;
        maxTotalScore += record.maxScore;
    });

    const percentage = maxTotalScore > 0 ? (totalScore / maxTotalScore * 100).toFixed(1) : "0.0";

    // 创建HTML表格内容
    let html = `
        <html xmlns:o="urn:schemas-microsoft-com:office:office" xmlns:x="urn:schemas-microsoft-com:office:excel" xmlns="http://www.w3.org/TR/REC-html40">
        <head>
            <meta charset="UTF-8">
            <title>巡店检查报告</title>
            <!--[if gte mso 9]>
            <xml>
                <x:ExcelWorkbook>
                    <x:ExcelWorksheets>
                        <x:ExcelWorksheet>
                            <x:Name>巡店检查报告</x:Name>
                            <x:WorksheetOptions>
                                <x:DisplayGridlines/>
                            </x:WorksheetOptions>
                        </x:ExcelWorksheet>
                    </x:ExcelWorksheets>
                </x:ExcelWorkbook>
            </xml>
            <![endif]-->
            <style>
                table {
                    border-collapse: collapse;
                    width: 100%;
                }
                th, td {
                    border: 1px solid #ddd;
                    padding: 8px;
                    text-align: left;
                }
                th {
                    background-color: #3498db;
                    color: white;
                }
                .deduction-item {
                    color: #e74c3c;
                    margin-left: 20px;
                }
            </style>
        </head>
        <body>
            <h1>巡店检查报告</h1>
            <p>检查人: ${inspectionData.inspector}</p>
            <p>门店名称: ${inspectionData.shop}</p>
            <p>检查日期: ${inspectionData.date}</p>
            <p>总检查人次: ${records.length}</p>

            <h2>总分: ${totalScore} / ${maxTotalScore} (${percentage}%)</h2>

            <h3>检查记录汇总</h3>
            <table>
                <tr>
                    <th>区域</th>
                    <th>员工</th>
                    <th>得分</th>
                    <th>满分</th>
                    <th>百分比</th>
                </tr>
    `;

    // 添加各记录得分
    records.forEach(record => {
        let areaName = record.name || "";
        // Fallback name logic if empty
        if (!areaName && record.areaKey) {
             // simplified fallback logic just in case
             areaName = record.areaKey;
        }

        const areaPercentage = record.maxScore > 0 ? (record.score / record.maxScore * 100).toFixed(1) : "0.0";

        html += `
            <tr>
                <td>${areaName}</td>
                <td>${record.employee || '-'}</td>
                <td>${record.score}</td>
                <td>${record.maxScore}</td>
                <td>${areaPercentage}%</td>
            </tr>
        `;
    });

    html += `
            </table>

            <h3>详细扣分项</h3>
    `;

    // 添加详细扣分项
    records.forEach(record => {
        if (record.deductions.length > 0) {
            html += `<h4>${record.name} (员工: ${record.employee || '未记录'})</h4><table>`;
            html += `
                <tr>
                    <th>检查项目</th>
                    <th>检查标准</th>
                    <th>得分</th>
                    <th>满分</th>
                    <th>扣分原因</th>
                </tr>
            `;

            record.deductions.forEach(deduction => {
                html += `
                    <tr>
                        <td>${deduction.item}</td>
                        <td>${deduction.standard}</td>
                        <td>${deduction.score}</td>
                        <td>${deduction.maxScore}</td>
                        <td>${deduction.criteria}</td>
                    </tr>
                `;
            });

            html += `</table>`;
        }
    });

    // 添加红线条款
    html += `<h3>红线条款</h3><ul>`;
    records.forEach(record => {
         html += `<li><strong>${record.name} (${record.employee}):</strong><ul>`;
         if (record.redLine && record.redLine.length > 0) {
             record.redLine.forEach(item => {
                 html += `<li>${item}</li>`;
             });
         } else {
             html += `<li>无</li>`;
         }
         html += `</ul></li>`;
    });
    html += `</ul>`;

    html += `
        </body>
        </html>
    `;

    // 创建Blob对象
    const blob = new Blob([html], { type: 'application/vnd.ms-excel' });

    // 创建下载链接
    const a = document.createElement('a');
    a.href = URL.createObjectURL(blob);
    a.download = `巡店检查报告_${inspectionData.shop}_${inspectionData.date.replace(/[: ]/g, '-')}.xls`;

    // 触发下载
    document.body.appendChild(a);
    a.click();

    // 清理
    setTimeout(() => {
        document.body.removeChild(a);
        URL.revokeObjectURL(a.href);
    }, 100);
}

import React, { useState, useEffect } from 'react';
import { InspectionData, ViewState, Areas, AreaData, Deduction, EmployeeConfig, InspectionRecord } from './types';
import { INITIAL_AREAS, INITIAL_EMPLOYEES } from './data';
import { exportToExcel } from './utils/excelExport';

const App: React.FC = () => {
    // Application State
    const [inspectionData, setInspectionData] = useState<InspectionData>(() => ({
        inspector: '',
        shop: '',
        date: '',
        areas: JSON.parse(JSON.stringify(INITIAL_AREAS)), // Deep copy to ensure fresh state
        records: [] // Store completed records here
    }));

    const [employees, setEmployees] = useState<EmployeeConfig>(INITIAL_EMPLOYEES);

    const [view, setView] = useState<ViewState>('inspector-info');
    const [currentAreaKey, setCurrentAreaKey] = useState<string>('');
    const [currentEmployee, setCurrentEmployee] = useState<string>(''); // Currently selected employee for inspection
    const [searchTerm, setSearchTerm] = useState<string>('');

    // For Area Selection View
    const [selectionAreaKey, setSelectionAreaKey] = useState<string>('');
    const [selectionEmployee, setSelectionEmployee] = useState<string>('');

    // For Management View
    const [manageAreaKey, setManageAreaKey] = useState<string>('vegetables');
    const [newEmployeeName, setNewEmployeeName] = useState<string>('');

    // Initialize Date
    useEffect(() => {
        const now = new Date();
        const formattedDate = now.getFullYear() + '-' + 
                             String(now.getMonth() + 1).padStart(2, '0') + '-' + 
                             String(now.getDate()).padStart(2, '0') + ' ' + 
                             String(now.getHours()).padStart(2, '0') + ':' + 
                             String(now.getMinutes()).padStart(2, '0');

        setInspectionData(prev => ({ ...prev, date: formattedDate }));
    }, []);

    // --- Actions ---

    const handleStartInspection = (inspector: string, shop: string) => {
        if (!inspector || !shop) {
            alert('请填写检查人姓名和门店名称');
            return;
        }
        setInspectionData(prev => ({ ...prev, inspector, shop }));
        setView('area-selection');
    };

    const handleEnterInspection = () => {
        if (!selectionAreaKey) {
            alert("请选择一个区域");
            return;
        }
        if (!selectionEmployee) {
            alert("请选择该区域的员工");
            return;
        }

        // Update current context
        setCurrentAreaKey(selectionAreaKey);
        setCurrentEmployee(selectionEmployee);

        // RESET Logic: When starting a new inspection for a specific employee, 
        // we must load a fresh copy of that area's data (scores reset to default)
        // so previous inspections don't interfere.
        setInspectionData(prev => {
            const newAreas = { ...prev.areas };
            // Get fresh data from INITIAL_AREAS
            const freshArea = JSON.parse(JSON.stringify(INITIAL_AREAS[selectionAreaKey]));

            // Assign the selected employee to this fresh instance
            freshArea.employee = selectionEmployee;

            newAreas[selectionAreaKey] = freshArea;

            return { ...prev, areas: newAreas };
        });

        setSearchTerm('');
        setView('inspection');
    };

    const handleViewResults = () => {
        setView('results');
    };

    const handleBackToAreas = () => {
        // Reset selection state
        setSelectionAreaKey('');
        setSelectionEmployee('');
        setView('area-selection');
    };

    const handleUpdateScore = (itemIndex: number, standardIndex: number, newScore: number) => {
        setInspectionData(prev => {
            // Create a deep enough copy to avoid direct mutation
            const newAreas = { ...prev.areas };
            const newArea = { ...newAreas[currentAreaKey] };

            // Deep copy items array to ensure React detects the change
            newArea.items = newArea.items.map((item, idx) => {
                if (idx !== itemIndex) return item;
                return {
                    ...item,
                    standards: item.standards.map((std, sIdx) => {
                        if (sIdx !== standardIndex) return std;
                        return { ...std, score: newScore };
                    })
                };
            });

            newAreas[currentAreaKey] = newArea;
            return { ...prev, areas: newAreas };
        });
    };

    const handleConfirmInspection = () => {
        if (!currentAreaKey) return;

        const currentArea = inspectionData.areas[currentAreaKey];
        if (!currentArea) return;

        // --- Calculation Logic ---
        let totalScore = 0;
        let maxScore = 0;
        const deductions: Deduction[] = [];

        currentArea.items.forEach(item => {
            item.standards.forEach(standard => {
                totalScore += standard.score;
                maxScore += standard.maxScore;

                if (standard.score < standard.maxScore) {
                    deductions.push({
                        item: item.name,
                        standard: standard.name,
                        score: standard.score,
                        maxScore: standard.maxScore,
                        criteria: standard.criteria
                    });
                }
            });
        });

        // --- State Update ---
        setInspectionData(prev => {
            // Create the finished record
            const newRecord: InspectionRecord = {
                ...currentArea,
                score: totalScore,
                maxScore: maxScore,
                completed: true,
                deductions: deductions,
                employee: currentEmployee,
                areaKey: currentAreaKey,
                id: Date.now().toString() // Simple ID
            };

            // Add to records list
            // We do NOT modify prev.areas in a way that blocks future inspections.
            // prev.areas is just the "working draft".

            return {
                ...prev,
                records: [...prev.records, newRecord]
            };
        });

        alert("提交成功！(Submitted Successfully)");
        handleBackToAreas();
    };

    const handleCancelInspection = () => {
         if (window.confirm('确定要取消当前检查吗？未保存的评分将丢失。')) {
            handleBackToAreas();
        }
    };

    // Management Actions
    const handleAddEmployee = () => {
        if (!newEmployeeName.trim()) return;
        setEmployees(prev => ({
            ...prev,
            [manageAreaKey]: [...(prev[manageAreaKey] || []), newEmployeeName.trim()]
