    const renderResultsPage = () => {
        // --- Aggregation Logic ---
        // Group records by Employee + Area to calculate averages
        const aggregatedData = inspectionData.records.reduce((acc, record) => {
            const key = `${record.areaKey}_${record.employee}`;
            if (!acc[key]) {
                acc[key] = {
                    name: record.name,
                    areaKey: record.areaKey,
                    employee: record.employee || 'Unknown',
                    totalScore: 0,
                    maxScore: record.maxScore, // Assuming max score is constant for the area
                    count: 0,
                    deductions: [],
                    records: [] // Keep reference to individual records if needed
                };
            }
            acc[key].totalScore += record.score;
            acc[key].count += 1;
            acc[key].deductions.push(...record.deductions);
            acc[key].records.push(record);
            return acc;
        }, {} as Record<string, {
            name?: string,
            areaKey: string,
            employee: string,
            totalScore: number,
            maxScore: number,
            count: number,
            deductions: Deduction[],
            records: any[]
        }>);

        const results = Object.values(aggregatedData).map(item => {
            const avgScore = Number((item.totalScore / item.count).toFixed(1));
            return {
                ...item,
                avgScore
            };
        });

        // Calculate Totals based on Averages
        // Total Shop Score = Sum of Employee Averages
        const totalAvgScoreSum = results.reduce((sum, item) => sum + item.avgScore, 0);
        const totalMaxScoreSum = results.reduce((sum, item) => sum + item.maxScore, 0);

        // Format for display
        const displayTotalScore = totalAvgScoreSum.toFixed(1);
        const overallPercentage = totalMaxScoreSum > 0 ? (totalAvgScoreSum / totalMaxScoreSum * 100).toFixed(1) : '0';

        return (
            <div id="results-page">
                <div className="bg-[#3498db] text-white p-[15px] rounded-[5px] mb-[20px]">
                    <h2 className="text-center text-xl font-bold">巡店检查结果汇总</h2>
                    <p className="text-center mt-2">检查人: <span>{inspectionData.inspector}</span> | 门店: <span>{inspectionData.shop}</span> | 日期: <span>{inspectionData.date}</span></p>
                    <p className="text-center text-sm mt-1">(注: 同一员工多次检查已取平均分)</p>
                </div>

                <div className="text-[18px] font-bold my-[20px] text-center">
                    总分 (Sum of Averages): <span>{displayTotalScore}</span> / <span>{totalMaxScoreSum}</span>
                    (<span>{overallPercentage}</span>%)
                </div>

                <table className="w-full border-collapse my-[20px]">
                    <thead>
                        <tr>
                            <th className="border border-[#ddd] p-[8px] text-left bg-[#3498db] text-white">区域 (Area)</th>
                            <th className="border border-[#ddd] p-[8px] text-left bg-[#3498db] text-white">员工 (Employee)</th>
                            <th className="border border-[#ddd] p-[8px] text-left bg-[#3498db] text-white">检查次数 (Count)</th>
                            <th className="border border-[#ddd] p-[8px] text-left bg-[#3498db] text-white">平均分 (Avg Score)</th>
                            <th className="border border-[#ddd] p-[8px] text-left bg-[#3498db] text-white">满分 (Max)</th>
                            <th className="border border-[#ddd] p-[8px] text-left bg-[#3498db] text-white">得分率 (%)</th>
                        </tr>
                    </thead>
                    <tbody>
                        {results.map((data, idx) => {
                            const pct = data.maxScore > 0 ? (data.avgScore / data.maxScore * 100).toFixed(1) : '0';
                            return (
                                <tr key={idx} className={idx % 2 === 0 ? "bg-[#f2f2f2]" : ""}>
                                    <td className="border border-[#ddd] p-[8px]">{data.name}</td>
                                    <td className="border border-[#ddd] p-[8px] font-bold text-blue-600">{data.employee}</td>
                                    <td className="border border-[#ddd] p-[8px] text-center">{data.count}</td>
                                    <td className="border border-[#ddd] p-[8px] font-bold">{data.avgScore}</td>
                                    <td className="border border-[#ddd] p-[8px]">{data.maxScore}</td>
                                    <td className="border border-[#ddd] p-[8px]">{pct}%</td>
                                </tr>
                            );
                        })}
                    </tbody>
                </table>

                <div className="mt-[30px]">
                    <h3 className="text-[#2c3e50] font-bold text-center text-lg mb-2">详细扣分项汇总:</h3>
                    {results.map((data, idx) => {
                        if (data.deductions.length === 0) return null;
                        return (
                            <div key={idx} className="mb-6 border-b pb-4">
                                <h4 className="text-[#2c3e50] font-bold mt-4 mb-2">
                                    {data.name} ({data.employee}) - 平均分: {data.avgScore}
                                </h4>
                                <ul className="list-disc pl-5">
                                    {data.deductions.map((deduction, dIdx) => (
                                        <li key={dIdx} className="text-[#e74c3c] ml-[20px] mb-2">
                                            <strong>{deduction.item}</strong> - {deduction.standard}<br/>
                                            单次得分: {deduction.score}/{deduction.maxScore}<br/>
                                            扣分原因: {deduction.criteria}
                                        </li>
                                    ))}
                                </ul>
                            </div>
                        );
                    })}
                </div>

                <div className="text-center mt-[20px]">
                    <button 
                        type="button"
                        className="bg-[#27ae60] text-white border-none py-[10px] px-[15px] rounded-[4px] cursor-pointer text-[16px] m-[5px] hover:bg-[#219653] transition-colors duration-300"
                        onClick={() => exportToExcel(inspectionData)}
                    >
                        导出详细报告 (Excel)
                    </button>
                    <button 
                        type="button"
                        className="bg-[#7f8c8d] text-white border-none py-[10px] px-[15px] rounded-[4px] cursor-pointer text-[16px] m-[5px] hover:bg-[#6c7a7d] transition-colors duration-300"
                        onClick={handleBackToAreas}
                    >
                        返回继续检查
                    </button>
                </div>
            </div>
        );
    };

    return (
        <div className="container max-w-[1200px] mx-auto bg-white p-[10px] md:p-[20px] rounded-[8px] shadow-[0_0_10px_rgba(0,0,0,0.1)]">
            {view === 'inspector-info' && renderInspectorInfo()}
            {view === 'management' && renderManagement()}
            {view === 'area-selection' && renderAreaSelection()}
            {view === 'inspection' && renderInspectionPage()}
            {view === 'results' && renderResultsPage()}
        </div>
    );
};

