            setEmployees(prev => ({
                ...prev,
                [manageAreaKey]: prev[manageAreaKey].filter(name => name !== nameToDelete)
            }));
        }
    };

    // **UPDATED**: Delete from Firebase
    const handleDeleteRecord = async (recordId: string) => {
