                <h2 className="text-xl font-bold">人员管理后台</h2>
                <button 
                    onClick={() => setView('inspector-info')}
                    className="bg-transparent border border-white text-white px-3 py-1 rounded hover:bg-white hover:text-[#3498db]"
                >
