            { key: 'deli', label: '熟食区', sub: 'Deli' },
            { key: 'cashier', label: '收银区域', sub: 'Cashier' }
        ];
        return (
            <div id="area-selection-page">
                <div className="bg-[#3498db] text-white p-[15px] rounded-[5px] mb-[20px] relative">
